INSERT INTO `auteur` (`idAuteur`, `nom`, `prenom`, `description`, `status`, `dateNaiss`, `image`) VALUES
(1, 'Collins', 'Suzanne', 'Suzanne Collins is an American author and television writer born on August 10, 1962, in Hartford, Connecticut. She grew up in a military family and her father\'s career as an Air Force officer deeply influenced her writing, particularly her interest in war and its impact on children. Collins began her career writing for children\'s television, contributing to shows such as Clarissa Explains It All and Little Bear. Her breakthrough came with The Underland Chronicles series before she achieved global fame with The Hunger Games trilogy, which explores themes of survival, media manipulation, and political oppression. The series became a cultural phenomenon, selling over 100 million copies worldwide and inspiring a major film franchise. Collins drew inspiration for the story from channel-surfing between reality TV and war footage, as well as from the Greek myth of Theseus and the Minotaur.', 'Alive', '1962-08-10', 'author-1-suzanne-collins.jpg'),
(2, 'Rowling', 'J.K.', 'Joanne Rowling, known by her pen name J.K. Rowling, was born on July 31, 1965, in Yate, Gloucestershire, England. She is one of the most celebrated authors in history, best known as the creator of the Harry Potter series. Before achieving fame, Rowling faced significant personal hardships, including the death of her mother, a difficult divorce, and a period of poverty while raising her daughter as a single mother in Edinburgh, Scotland. It was during this difficult time that she wrote the first Harry Potter novel in local cafés. Published in 1997, Harry Potter and the Philosopher\'s Stone launched one of the most successful literary franchises of all time, with the seven-book series selling over 500 million copies worldwide and being translated into more than 85 languages. Rowling has since become a philanthropist and has also written crime fiction under the pseudonym Robert Galbraith.', 'Alive', '1965-07-31', 'author-2-jk-rowling.jpg'),
(3, 'GrandPré', 'Mary', 'Mary GrandPré is an American illustrator and artist born on December 23, 1954, in South Dakota. She is best known for creating the iconic cover illustrations and chapter heading artwork for the American editions of J.K. Rowling\'s Harry Potter series, published by Scholastic. Her warm, painterly style helped define the visual identity of the Harry Potter books in the United States, and her images became as recognizable as the stories themselves. Before her work on Harry Potter, GrandPré had established herself as a successful commercial illustrator whose work appeared on magazine covers and in advertising campaigns. She has also illustrated several of her own picture books for children. Her contributions to the Harry Potter universe earned her widespread recognition and a permanent place in literary and artistic history.', 'Alive', '1954-12-23', 'author-3-mary-grandpré.jpg'),
(4, 'Meyer', 'Stephenie', 'Stephenie Meyer is an American novelist born on December 24, 1973, in Hartford, Connecticut. She grew up in Scottsdale, Arizona, and studied English literature at Brigham Young University, where she graduated with a degree in 1997. Before becoming an author, Meyer worked as a homemaker raising her three sons. Her career as a writer began unexpectedly in 2003 when she had a vivid dream that inspired what would become the first chapter of Twilight. She completed the novel in just three months and secured a publishing deal that launched one of the most successful young adult series of all time. The Twilight saga, consisting of four novels, sold over 100 million copies worldwide and was adapted into a blockbuster film franchise. Meyer\'s work revitalized the vampire romance genre and introduced a new generation of readers to paranormal fiction.', 'Alive', '1973-12-24', 'author-4-stephenie-meyer.jpg'),
(5, 'Lee', 'Harper', 'Nelle Harper Lee was an American novelist born on April 28, 1926, in Monroeville, Alabama. She is best known for her Pulitzer Prize-winning novel To Kill a Mockingbird, published in 1960, which explores themes of racial injustice and moral growth in the American South through the eyes of young Scout Finch. Lee studied law at the University of Alabama but left before completing her degree to pursue her dream of becoming a writer in New York City. She was a childhood friend of the author Truman Capote, who inspired the character of Dill in her novel. To Kill a Mockingbird became an immediate bestseller and was adapted into an Academy Award-winning film in 1962. For decades, Lee was famously reclusive and published no new work, making the 2015 release of Go Set a Watchman, an earlier draft of her famous novel, a major literary event. She passed away on February 19, 2016.', 'Dead', '1926-04-28', 'author-5-harper-lee.jpg'),
(6, 'Scott Fitzgerald', 'F.', 'Francis Scott Key Fitzgerald was an American novelist and short story writer born on September 24, 1896, in Saint Paul, Minnesota. He is widely regarded as one of the greatest American writers of the twentieth century and a defining voice of the Jazz Age, a term he himself coined. Fitzgerald attended Princeton University but left to join the army during World War I, where he met his future wife, the socialite Zelda Sayre. His debut novel, This Side of Paradise, brought him early fame and allowed him to marry Zelda and live a glamorous but turbulent life. His masterpiece, The Great Gatsby, published in 1925, is a searing critique of the American Dream, wealth, and moral decay. Despite his talent, Fitzgerald struggled throughout his life with alcoholism and financial difficulties. He died on December 21, 1940, largely forgotten, but his reputation was posthumously restored and he is now considered one of literature\'s great figures.', 'Dead', '1896-09-24', 'author-6-f-scott-fitzgerald.jpg'),
(7, 'Green', 'John', 'John Green is an American author and online content creator born on August 24, 1977, in Indianapolis, Indiana. He studied English and religious studies at Kenyon College and briefly worked as a student chaplain before turning to writing. His debut novel Looking for Alaska won the 2006 Printz Award and established him as a leading voice in young adult fiction. Green is known for his emotionally honest portrayals of adolescence, illness, love, and grief. His novel The Fault in Our Stars, published in 2012, became a massive international bestseller and was adapted into a successful film. Along with his brother Hank, Green co-founded the VlogBrothers YouTube channel, which sparked the Nerdfighter community and various charitable projects. He has become one of the most influential authors in the young adult genre and a significant figure in internet culture.', 'Alive', '1977-08-24', 'author-7-john-green.jpg'),
(8, 'Tolkien', 'J.R.R.', 'John Ronald Reuel Tolkien was a British author, poet, and academic born on January 3, 1892, in Bloemfontein, South Africa. He is best known as the creator of the richly detailed fantasy world of Middle-earth, depicted in his works The Hobbit and the monumental Lord of the Rings trilogy. Tolkien served in World War I at the Battle of the Somme, an experience that profoundly influenced his writing. He became a professor of Anglo-Saxon at the University of Oxford and was a close friend of C.S. Lewis, with both men being members of the literary discussion group known as the Inklings. Tolkien devoted decades to constructing the languages, mythology, and history of Middle-earth, much of which was published posthumously in The Silmarillion. His work essentially founded the modern fantasy genre and continues to inspire writers, filmmakers, and readers around the world. He passed away on September 2, 1973.', 'Dead', '1892-01-03', 'author-8-jrr-tolkien.jpg'),
(9, 'Salinger', 'J.D.', 'Jerome David Salinger was an American author born on January 1, 1919, in New York City. He is best known for his 1951 novel The Catcher in the Rye, narrated by the iconic and rebellious teenager Holden Caulfield. The novel became one of the most controversial and widely read books of the twentieth century, addressing themes of adolescent alienation, identity, and the loss of innocence. Salinger served in World War II, participating in the Normandy invasion, an experience that left deep psychological scars and influenced much of his writing. After a brief period of literary fame, he became increasingly reclusive, retreating to Cornish, New Hampshire, and refusing interviews, public appearances, and the publication of new work for decades. He did continue to write privately, and works may yet be released posthumously. Salinger passed away on January 27, 2010, leaving behind a small but enduring literary legacy.', 'Dead', '1919-01-01', 'author-9-jd-salinger.jpg'),
(10, 'Brown', 'Dan', 'Dan Brown is an American author born on June 22, 1964, in Exeter, New Hampshire. He studied English and Spanish at Amherst College and spent time as a musician and songwriter before turning to writing thrillers. His early novels, including Digital Fortress and Angels and Demons, built a modest following, but it was The Da Vinci Code, published in 2003, that catapulted him to global fame. The novel blends art history, cryptography, religious conspiracy, and fast-paced action, becoming one of the best-selling novels of all time with over 80 million copies sold. The book sparked widespread debate about the history of Christianity and the Catholic Church. Brown\'s novels featuring the symbologist Robert Langdon have all been adapted into major Hollywood films. He is known for his meticulous research and for weaving real historical locations and artworks into his fictional narratives.', 'Alive', '1964-06-22', 'author-10-dan-brown.jpg'),
(11, 'Austen', 'Jane', 'Jane Austen was an English novelist born on December 16, 1775, in Steventon, Hampshire, England. She is one of the most celebrated writers in the English language, known for her sharp wit, social commentary, and nuanced portrayals of women navigating the rigid class structures and marriage markets of Regency-era England. Austen wrote her novels largely in secret, often hiding her manuscripts when visitors arrived, as writing was not considered a respectable occupation for women of her class. Her major works include Sense and Sensibility, Pride and Prejudice, Mansfield Park, Emma, Northanger Abbey, and Persuasion. Pride and Prejudice, with its unforgettable heroine Elizabeth Bennet and the brooding Mr. Darcy, remains one of the most beloved novels ever written. Austen never married and lived much of her life with her family, drawing on her keen observations of society for her fiction. She died on July 18, 1817, at the age of 41, leaving a literary legacy that has only grown with time.', 'Dead', '1775-12-16', 'author-11-jane-austen.jpg'),
(12, 'Hosseini', 'Khaled', 'Khaled Hosseini is an Afghan-American novelist and physician born in 1965 in Kabul, Afghanistan. His father was a diplomat, and the family was granted asylum in the United States in 1980 following the Soviet invasion of Afghanistan. Hosseini studied medicine at the University of California San Diego and worked as a doctor for over a decade before becoming a full-time writer. His debut novel, The Kite Runner, published in 2003, became an international bestseller, offering Western readers an intimate and emotionally powerful portrait of Afghanistan across decades of war and upheaval. His second novel, A Thousand Splendid Suns, focused on the lives of Afghan women under the Taliban. Hosseini has also served as a United Nations Goodwill Ambassador for the UNHCR, using his platform to raise awareness for Afghan refugees. His work has brought the stories and suffering of the Afghan people to a worldwide audience.', 'Alive', '1965-03-04', 'author-12-khaled-hosseini.jpg'),
(13, 'Roth', 'Veronica', 'Veronica Roth is an American novelist born on August 19, 1988, in New York City. She grew up in Barrington, Illinois, and studied creative writing at Northwestern University. Remarkably, she wrote the first book of her Divergent trilogy while still a college student, completing it during winter break of her senior year. Divergent, published in 2011, introduced the dystopian world of a future Chicago divided into factions based on human virtues. The novel became a huge success in the young adult genre and was followed by Insurgent and Allegiant. The trilogy was adapted into a film series starring Shailene Woodley. Roth\'s willingness to make bold and controversial narrative choices, including an unexpected ending in Allegiant, demonstrated her commitment to storytelling over commercial expectations. She has continued to write speculative fiction for both young adult and adult audiences.', 'Alive', '1988-08-19', 'author-13-veronica-roth.jpg'),
(14, 'Frank', 'Anne', 'Annelies Marie Frank was a German-born Jewish diarist born on June 12, 1929, in Frankfurt, Germany. Her family fled to the Netherlands after the rise of the Nazi regime, but following the German occupation of the Netherlands, they went into hiding in a concealed apartment in Amsterdam in July 1942. Anne received a diary as a birthday gift and wrote in it throughout the two years the family spent in hiding. In August 1944, the family was betrayed and arrested, and Anne was deported to the Bergen-Belsen concentration camp, where she died of typhus in February or March of 1945, just weeks before the camp was liberated. Her father Otto Frank, the only family member to survive the Holocaust, arranged for the diary to be published. The Diary of a Young Girl, first published in Dutch in 1947, has since been translated into over 70 languages and remains one of the most widely read accounts of the Holocaust, serving as a powerful testament to human dignity and resilience.', 'Dead', '1929-06-12', 'author-14-anne-frank.jpg'),
(15, 'Roosevelt', 'Eleanor', 'Anna Eleanor Roosevelt was an American political figure, diplomat, and activist born on October 11, 1884, in New York City. She served as First Lady of the United States from 1933 to 1945 as the wife of President Franklin D. Roosevelt, but her influence extended far beyond the traditional role of First Lady. Roosevelt was a passionate advocate for civil rights, women\'s rights, and social justice, and she used her platform to challenge racial segregation at a time when it was politically risky to do so. After her husband\'s death in 1945, President Truman appointed her as a delegate to the United Nations, where she chaired the committee that drafted the Universal Declaration of Human Rights, adopted in 1948. She was a prolific writer, authoring several books including her autobiography On My Own and a daily syndicated newspaper column, My Day. She passed away on November 7, 1962, and is widely regarded as one of the most impactful and admired women of the twentieth century.', 'Dead', '1884-10-11', 'author-15-eleanor-roosevelt.jpg'),
(16, 'Mooyaart-Doubleday', 'B.M.', 'B.M. Mooyaart-Doubleday was a Dutch translator best known for producing the first English-language translation of Anne Frank\'s diary, Het Achterhuis, which was published in English in 1952 under the title Anne Frank: The Diary of a Young Girl. Her translation brought Anne Frank\'s story to English-speaking readers around the world and played a crucial role in establishing the diary as one of the most important documents of the Holocaust. Little is publicly known about Mooyaart-Doubleday\'s personal life and career beyond her contribution to this landmark translation, but her work ensured that Anne Frank\'s words and experiences reached a global audience that might otherwise never have encountered them.', 'Dead', '1903-06-01', 'author-16-bm-mooyaart-doubleday.jpg'),
(17, 'Larsson', 'Stieg', 'Karl Stig-Erland Larsson was a Swedish journalist, author, and activist born on August 15, 1954, in Skellefteå, Sweden. He spent the majority of his professional life as a journalist and editor, becoming one of Sweden\'s foremost experts on right-wing extremism and co-founding the Expo Foundation, which monitored and exposed antidemocratic movements. Larsson also wrote crime fiction in his spare time and completed three manuscripts comprising the Millennium series shortly before his death. Tragically, he died of a heart attack in November 2004 at the age of 50, without knowing that his novels would become a global phenomenon. The Girl with the Dragon Tattoo, The Girl Who Played with Fire, and The Girl Who Kicked the Hornets\' Nest were published posthumously between 2005 and 2007 and sold over 80 million copies worldwide. His fearless protagonist Lisbeth Salander became one of fiction\'s most iconic characters.', 'Dead', '1964-08-15', 'author-17-stieg-larsson.jpg'),
(18, 'Keeland', 'Reg', 'Reg Keeland is the pen name used by Steven T. Murray for his translations of Swedish crime fiction into English. He is best known for translating Stieg Larsson\'s Millennium trilogy, including The Girl with the Dragon Tattoo, which introduced millions of English-speaking readers to Larsson\'s gripping narrative world. Murray\'s translation work played a critical role in the global success of the Millennium series, and his ability to capture the tone, atmosphere, and cultural nuances of the original Swedish texts has been widely praised. Through his careful and skilled translations, he helped ensure that Larsson\'s powerful social commentary and compelling characters resonated authentically with international audiences.', 'Alive', '1944-01-01', 'author-18-reg-keeland.jpg'),
(19, 'Beck', 'Rufus', 'Rufus Beck is a German actor and narrator born in 1952 in Freiburg im Breisgau, Germany. He is widely celebrated in German-speaking countries as the voice actor who narrated the German audiobook editions of J.K. Rowling\'s Harry Potter series, bringing the characters to life with extraordinary skill and range. His vivid vocal performances became beloved by generations of German children and adults, and his interpretation of characters like Dumbledore, Voldemort, and Harry himself are considered definitive in the German-speaking world. Beyond his audiobook work, Beck has had a distinguished career as a stage and screen actor, performing in theater productions, films, and television series across Germany.', 'Alive', '1958-07-04', 'author-19-rufus-beck.jpg'),
(20, 'Sebold', 'Alice', 'Alice Sebold is an American author born in 1963 in Madison, Wisconsin. She is best known for her debut novel The Lovely Bones, published in 2002, which became one of the fastest-selling novels in history, spending over a year on the New York Times bestseller list. The story is narrated by a fourteen-year-old girl who watches from heaven as her family and community cope with the aftermath of her rape and murder. Sebold had previously published Lucky, a memoir about her own experience of being raped as a college freshman at Syracuse University and the subsequent legal proceedings. The emotional rawness of her memoir and the innovative narrative perspective of The Lovely Bones established her as one of the most distinctive voices in contemporary American fiction. The Lovely Bones was adapted into a major film directed by Peter Jackson in 2009.', 'Alive', '1963-09-06', 'author-20-alice-sebold.jpg'),
(21, 'Golding', 'William', 'Sir William Gerald Golding was a British novelist, playwright, and poet born on September 19, 1911, in Newquay, Cornwall, England. He is best known for his debut novel Lord of the Flies, published in 1954, a dark allegorical tale of British boys stranded on a deserted island who descend into savagery. The novel was rejected by dozens of publishers before finally being accepted and went on to become a seminal work of twentieth-century literature, widely taught in schools around the world. Golding served in the Royal Navy during World War II, participating in the D-Day landings, and his experiences of human cruelty during the war profoundly shaped his worldview and writing. He was awarded the Nobel Prize in Literature in 1983. His other major works include The Inheritors, Pincher Martin, and the sea trilogy To the Ends of the Earth. Golding was knighted in 1988 and passed away on June 19, 1993.', 'Dead', '1911-09-19', 'author-21-william-golding.jpg'),
(22, 'Shakespeare', 'William', 'William Shakespeare was an English playwright, poet, and actor widely regarded as the greatest writer in the English language and the world\'s greatest dramatist. Born on April 23, 1564, in Stratford-upon-Avon, England, he grew up in a prosperous household and received a classical education at the local grammar school. Shakespeare moved to London in the late 1580s and established himself as a leading playwright with the theatrical company the Lord Chamberlain\'s Men, later known as the King\'s Men. Over the course of his career, he wrote 39 plays, 154 sonnets, and several longer poems. His works range from comedies such as A Midsummer Night\'s Dream and Much Ado About Nothing to tragedies such as Hamlet, Othello, King Lear, and Macbeth, as well as historical plays and romances. Shakespeare retired to Stratford around 1613 and died on April 23, 1616. His influence on literature, language, and culture is immeasurable, and his works are performed and studied across the world.', 'Dead', '1564-04-23', 'author-22-william-shakespeare.jpg'),
(23, 'Jackson', 'Robert', 'Robert Jackson is a British author and aviation historian born in 1941, known for his extensive writings on military history, air warfare, and combat aviation. He has authored numerous books covering topics such as fighter aces of World War II, military aircraft, and naval history. His work is characterized by thorough research and an ability to convey the personal experiences of pilots and servicemen with clarity and narrative depth. Jackson has contributed significantly to the documentation of aerial combat history, and his books have been used as reference works by historians and aviation enthusiasts alike.', 'Alive', '1941-12-29', 'author-23-robert-jackson.jpg'),
(24, 'Flynn', 'Gillian', 'Gillian Flynn is an American author and screenwriter born on February 24, 1971, in Kansas City, Missouri. She studied journalism and English at the University of Kansas and later earned a master\'s degree in journalism from Northwestern University. Flynn spent over a decade as an entertainment writer and critic at Entertainment Weekly before publishing her debut novel Sharp Objects in 2006. Her psychological thrillers are known for their dark tone, complex female characters, and subversive approach to genre conventions. Her third novel, Gone Girl, published in 2012, became a massive international bestseller and was adapted into a critically acclaimed film directed by David Fincher in 2014. Flynn wrote the screenplay adaptation herself. She has become one of the most influential voices in contemporary crime fiction, helping to popularize the unreliable narrator and the morally ambiguous female protagonist.', 'Alive', '1971-02-24', 'author-24-gillian-flynn.jpg'),
(25, 'Stockett', 'Kathryn', 'Kathryn Stockett is an American author born in 1969 in Jackson, Mississippi. She grew up in the Deep South and was raised in part by a beloved African American housekeeper, an experience that inspired her debut novel, The Help. Stockett moved to New York City after college and worked in magazine publishing for several years before writing The Help over the course of five years. The novel, set in 1960s Mississippi, tells the story of black maids working for white families during the civil rights era and the white woman who helps them share their stories. The Help was rejected by 60 literary agents before finally being published in 2009, going on to become a massive bestseller and spend over 100 weeks on the New York Times bestseller list. It was adapted into an Academy Award-nominated film in 2011. Stockett\'s novel sparked important conversations about race, class, and the silencing of minority voices.', 'Alive', '1969-02-08', 'author-25-kathryn-stockett.jpg'),
(26, 'Steinbeck', 'John', 'John Ernst Steinbeck Jr. was an American author born on February 27, 1902, in Salinas, California. He is one of the most important figures in American literature, known for his portrayal of the working class and the struggles of ordinary people during the Great Depression. Steinbeck studied at Stanford University but left without a degree and worked a series of manual labor jobs that gave him direct experience of the lives he would later portray in his fiction. His novel Of Mice and Men, published in 1937, and The Grapes of Wrath, published in 1939, cemented his reputation as a champion of the dispossessed. The Grapes of Wrath, which follows the Joad family as they migrate from the Dust Bowl to California in search of a better life, won the Pulitzer Prize and is considered an American masterpiece. Steinbeck was awarded the Nobel Prize in Literature in 1962. He passed away on December 20, 1968.', 'Dead', '1902-02-27', 'author-26-john-steinbeck.jpg'),
(27, 'Golden', 'Arthur', 'Arthur Golden is an American author born on December 6, 1956, in Chattanooga, Tennessee. He studied art history at Harvard University and later earned a master\'s degree in Japanese history from Columbia University and an English degree from Boston University. Golden worked in the business field and as a magazine editor before publishing his debut and only novel, Memoirs of a Geisha, in 1997. The novel, narrated by a fictional Japanese geisha named Sayuri, drew on years of research into Japanese culture, history, and the geisha tradition. It became a major international bestseller and was adapted into a film in 2005. The book was praised for its immersive storytelling and lush historical detail, though it also attracted criticism from some within Japan and the geisha community regarding its portrayal of their world.', 'Alive', '1956-12-06', 'author-27-arthur-golden.jpg'),
(28, 'James', 'E.L.', 'Erika Leonard, known by her pen name E.L. James, is a British author born on March 7, 1963, in London, England. Before becoming one of the world\'s bestselling authors, she worked for over twenty years as a television executive. James originally published her story online as fan fiction inspired by the Twilight series, before reworking it into the novel Fifty Shades of Grey, published in 2011. The novel and its sequels, Fifty Shades Darker and Fifty Shades Freed, sparked global controversy and fascination for their explicit romantic content. The trilogy sold over 150 million copies worldwide, making James one of the bestselling authors of all time. The phenomenon of Fifty Shades of Grey is credited with bringing erotic fiction to mainstream audiences and demonstrating the commercial power of fan fiction and self-publishing. The trilogy was adapted into a Hollywood film series.', 'Alive', '1963-03-07', 'author-28-el-james.jpg'),
(29, 'Lowry', 'Lois', 'Lois Lowry is an American children\'s and young adult author born on March 20, 1937, in Honolulu, Hawaii. She is the author of more than forty novels, including two Newbery Medal winners: Number the Stars, a story of the Danish resistance during World War II, and The Giver, a dystopian novel published in 1993. The Giver is set in a seemingly perfect society where all pain and conflict have been eliminated, exploring themes of memory, freedom, and the cost of conformity. It became one of the most celebrated and also most banned books in American schools. Lowry grew up in a military family and lived in many different countries, experiences that influenced her perspective as a writer. Her personal tragedy of losing her son to a military accident shaped much of her later work. The Giver was eventually adapted into a film in 2014 and spawned a four-book series.', 'Alive', '1937-03-20', 'author-29-lois-lowry.jpg'),
(30, 'Lewis', 'C.S.', 'Clive Staples Lewis was a British writer and Christian apologist born on November 29, 1898, in Belfast, Ireland. He is best known for two bodies of work: his allegorical fantasy series The Chronicles of Narnia, beloved by generations of children worldwide, and his Christian apologetics writing, including Mere Christianity and The Screwtape Letters. Lewis served in World War I and was wounded in action. He studied and later taught English literature at both Oxford University and Cambridge University, becoming a highly respected academic. He was a close friend and fellow Inkling with J.R.R. Tolkien, who played a significant role in Lewis\'s conversion to Christianity. The Chronicles of Narnia, beginning with The Lion, the Witch and the Wardrobe, have sold over 100 million copies and been adapted for stage, screen, and radio. Lewis passed away on November 22, 1963, the same day as John F. Kennedy\'s assassination.', 'Dead', '1898-11-29', 'author-30-cs-lewis.jpg'),
(31, 'Niffenegger', 'Audrey', 'Audrey Niffenegger is an American author and visual artist born on June 13, 1963, in South Haven, Michigan. She studied art at the School of the Art Institute of Chicago, where she later taught for many years as a professor in the Interdisciplinary Book Arts program. Her debut novel, The Time Traveler\'s Wife, was published in 2003 after being rejected by numerous publishers. The novel tells the love story of Clare and Henry, whose relationship is complicated by Henry\'s involuntary time travel, and became a critically acclaimed international bestseller. It was adapted into a film in 2009 and later into an HBO television series. Niffenegger\'s background as a visual artist deeply informs her writing, and she has also published several illustrated books and graphic novels. Her second novel, Her Fearful Symmetry, was published in 2009 and is set partly in Highgate Cemetery in London.', 'Alive', '1963-06-13', 'author-31-audrey-niffenegger.jpg'),
(32, 'R.R. Martin', 'George', 'George Raymond Richard Martin is an American novelist, screenwriter, and television producer born on September 20, 1948, in Bayonne, New Jersey. He is best known as the author of the epic fantasy series A Song of Ice and Fire, which began with A Game of Thrones in 1996. The series, known for its sprawling cast of morally complex characters, political intrigue, and willingness to kill off major characters, revolutionized the fantasy genre. Martin worked in Hollywood as a television writer and producer for many years before returning to novels. The television adaptation Game of Thrones, produced by HBO, became one of the most watched and discussed television shows in history, running from 2011 to 2019. Martin is also known for his earlier work in science fiction and horror, as well as editing the Wild Cards shared universe anthology series. Fans worldwide eagerly await the conclusion of his unfinished saga.', 'Alive', '1948-09-20', 'author-32-george-rr-martin.jpg'),
(33, 'Gilbert', 'Elizabeth', 'Elizabeth Gilbert is an American author born in 1969 in Waterbury, Connecticut. She studied political science at New York University and worked as a bartender, cook, and journalist before becoming a full-time author. Gilbert first gained recognition for her fiction and her work as a journalist for magazines including GQ and Spin. However, it was her memoir Eat, Pray, Love, published in 2006, that brought her worldwide fame. The book chronicles her year of travel through Italy, India, and Indonesia following a difficult divorce, exploring themes of self-discovery, spirituality, and pleasure. It became a massive bestseller, spending over three years on the New York Times bestseller list, and was adapted into a film starring Julia Roberts in 2010. Gilbert has also written novels, including The Signature of All Things and City of Girls, and her TED talk on creativity has been viewed by millions of people.', 'Alive', '1969-07-18', 'author-33-elizabeth-gilbert.jpg'),
(34, 'Riordan', 'Rick', 'Richard Russell Riordan Jr. is an American author born on June 5, 1964, in San Antonio, Texas. He worked as a middle school English and history teacher for fifteen years in San Antonio before becoming a full-time author. Riordan created the character of Percy Jackson to tell stories to his son, who has ADHD and dyslexia. In the Percy Jackson universe, these traits are reframed as markers of a demigod heritage, giving children with learning differences a heroic role model. The Percy Jackson and the Olympians series, which reimagines Greek mythology in modern America, became a massive success with young readers worldwide. Riordan has since expanded his mythological universe to include Egyptian, Norse, and Roman mythologies, creating multiple interconnected series. He is also known for actively championing diverse representation in children\'s literature and for his advocacy for readers with learning differences.', 'Alive', '1964-06-05', 'author-34-rick-riordan.jpg'),
(35, 'May Alcott', 'Louisa', 'Louisa May Alcott was an American novelist and poet born on November 29, 1832, in Germantown, Pennsylvania. She grew up in a transcendentalist family in Concord, Massachusetts, and was deeply influenced by her father Bronson Alcott, a progressive educator and philosopher, as well as by family friends including Ralph Waldo Emerson and Henry David Thoreau. Alcott worked from a young age to support her family, taking on jobs as a seamstress, teacher, and domestic servant before establishing herself as a writer. During the Civil War, she served as an army nurse, an experience she documented in Hospital Sketches. Her most famous work, Little Women, published in 1868, drew heavily on her own childhood experiences growing up with three sisters. The novel became an immediate success and is considered a classic of American literature, beloved for its portrayal of independent-minded female characters. Alcott was also an active abolitionist and women\'s suffragist. She died on March 6, 1888.', 'Dead', '1832-11-29', 'author-35-louisa-may-alcott.jpg'),
(36, 'Brontë', 'Charlotte', 'Charlotte Brontë was an English novelist and poet born on April 21, 1816, in Thornton, Yorkshire, England. She was the eldest of the three famous Brontë sisters, all of whom became celebrated writers. Charlotte and her siblings grew up in the village of Haworth on the Yorkshire moors, where their father was a clergyman. The children created elaborate imaginary worlds and wrote prolifically from a young age. Charlotte worked as a teacher and governess before achieving literary success. Her masterpiece, Jane Eyre, published under the male pseudonym Currer Bell in 1847, was a groundbreaking novel that combined romance, Gothic atmosphere, and a strong feminist sensibility. Jane Eyre\'s first-person narrative voice and its themes of independence, morality, and passion made it one of the most influential novels of the Victorian era. Charlotte married her father\'s curate, Arthur Bell Nicholls, in 1854, but died the following year on March 31, 1855, possibly due to complications from pregnancy.', 'Dead', '1816-04-21', 'author-36-charlotte-brontë.jpg'),
(37, 'Mason', 'Michael', 'Michael Mason is an author and editor known for his work in the fields of literature, cultural commentary, and Victorian studies. He has written and edited several academic and general-interest works examining Victorian society, sexuality, and literature, contributing to scholarly understanding of the cultural and moral frameworks of nineteenth-century Britain. His writing is characterized by careful research and an ability to make complex historical and literary subjects accessible to general readers.', 'Alive', '1946-01-01', 'author-37-michael-mason.jpg'),
(38, 'Martel', 'Yann', 'Yann Martel is a Canadian author born on June 25, 1963, in Salamanca, Spain, to Canadian parents. He studied philosophy at Trent University in Ontario and worked a variety of jobs, including as a tree planter and dishwasher, before devoting himself to writing. After two less successful books, Martel published Life of Pi in 2001, a philosophical adventure novel about a young Indian boy who survives a shipwreck and spends 227 days on a lifeboat with a Bengal tiger named Richard Parker. The novel won the prestigious Man Booker Prize in 2002 and became a worldwide bestseller, eventually being adapted into a visually stunning Academy Award-winning film directed by Ang Lee in 2012. Life of Pi explores themes of faith, survival, storytelling, and the nature of reality. Martel has also written other novels and is known for sending books to former Canadian Prime Minister Stephen Harper as a political commentary.', 'Alive', '1963-06-25', 'author-38-yann-martel.jpg'),
(39, 'Gruen', 'Sara', 'Sara Gruen is an American-Canadian author born in 1969. She is best known for her novel Water for Elephants, published in 2006, a historical novel set in the world of a traveling Depression-era circus. The story follows a young veterinary student who joins the circus after a personal tragedy and falls in love with the star performer. Gruen conducted extensive research into circus life and history while writing the novel, and her vivid, immersive portrayal of that world brought it vividly to life. Water for Elephants spent over a year on the New York Times bestseller list and was adapted into a film starring Robert Pattinson and Reese Witherspoon in 2011. Gruen is also the author of Riding Lessons, Flying Changes, and Ape House, and is known for her deep love of animals and her activism on behalf of great apes.', 'Alive', '1969-07-22', 'author-39-sara-gruen.jpg'),
(40, 'Zusak', 'Markus', 'Markus Zusak is an Australian author born in 1975 in Sydney, Australia, to immigrant parents from Germany and Austria. He began writing as a teenager and published four young adult novels in Australia before achieving worldwide recognition. His fifth novel, The Book Thief, published in 2005, is narrated by Death and set in Nazi Germany, telling the story of a young girl named Liesel Meminger who steals books and shares them with others during the bombing of Munich. The novel became an international bestseller, selling over 16 million copies and spending over 230 weeks on the New York Times bestseller list. It was adapted into a film in 2013. Zusak spent over three years writing the book, and his meticulous craft and unconventional narrative voice earned him widespread critical acclaim. He is widely regarded as one of the most important authors in contemporary Australian and international literature.', 'Alive', '1975-06-23', 'author-40-markus-zusak.jpg'),
(41, 'Silverstein', 'Shel', 'Sheldon Allan Silverstein was an American poet, singer-songwriter, musician, composer, cartoonist, screenwriter, and author of children\'s books born on September 25, 1930, in Chicago, Illinois. He is best known for his poetry collections for children, including Where the Sidewalk Ends, A Light in the Attic, and Falling Up, which are celebrated for their wit, whimsy, and playful wordplay. Silverstein began his career as a cartoonist for Playboy magazine and also wrote songs, including A Boy Named Sue, famously recorded by Johnny Cash. His poetry books have sold tens of millions of copies worldwide and introduced generations of young readers to the joy of verse. He also wrote the children\'s book The Giving Tree, one of the best-selling children\'s books of all time. Silverstein passed away on May 10, 1999, leaving behind a legacy that continues to delight readers of all ages.', 'Dead', '1930-09-25', 'author-41-shel-silverstein.jpg'),
(42, 'Clare', 'Cassandra', 'Cassandra Clare is the pen name of Judith Lewis, an American fantasy author born in 1973. She grew up partly in various countries including England, France, and Switzerland due to her family\'s frequent relocations, experiences that gave her a cosmopolitan perspective that shows in her world-building. Before publishing novels, Clare was known in online fan fiction communities for her Harry Potter fan fiction. Her debut novel City of Bones, the first in The Mortal Instruments series, was published in 2007 and introduced the Shadowhunter world, a richly developed urban fantasy universe populated by demon hunters, warlocks, vampires, and faeries. The series became a major success, spawning multiple spin-off series including The Infernal Devices and The Dark Artifices, as well as a film and a television adaptation. Clare is one of the bestselling young adult fantasy authors working today, with a fiercely devoted global readership.', 'Alive', '1973-07-27', 'author-42-cassandra-clare.jpg'),
(43, 'Paolini', 'Christopher', 'Christopher Paolini is an American author born on November 17, 1983, in Southern California, who grew up in Paradise Valley, Montana. He is remarkable for having written his debut novel Eragon when he was just fifteen years old. After being homeschooled by his parents, Paolini began writing the novel as a personal project. His parents helped him self-publish the book in 2002, and Paolini spent nearly a year touring schools and libraries in medieval costume to promote it. The book came to the attention of author Carl Hiaasen, who recommended it to his publisher, leading to a major publishing deal. Eragon was officially published in 2003 and became a bestseller, launching the Inheritance Cycle. The fantasy series, set in the world of Alagaësia and featuring dragons and elves, sold tens of millions of copies worldwide. Paolini completed the four-book cycle and later published the science fiction novel To Sleep in a Sea of Stars in 2020.', 'Alive', '1983-11-17', 'author-43-christopher-paolini.jpg'),
(44, 'Adams', 'Douglas', 'Douglas Noel Adams was a British author, scriptwriter, and satirist born on March 11, 1952, in Cambridge, England. He is best known as the creator of The Hitchhiker\'s Guide to the Galaxy, which began as a BBC radio comedy broadcast in 1978 and was expanded into a bestselling series of five novels. The series blends science fiction with absurdist humor and philosophical musings, following the hapless human Arthur Dent as he travels the universe after Earth is demolished to make way for a hyperspace bypass. Adams studied English literature at St John\'s College, Cambridge, and worked as a writer and editor for Doctor Who before achieving fame with Hitchhiker\'s. He was a passionate advocate for environmentalism and technology, and his non-fiction work Last Chance to See documented endangered species. Adams passed away suddenly of a heart attack on May 11, 2001, at the age of 49, leaving behind a devoted global following.', 'Dead', '1952-03-11', 'author-44-douglas-adams.jpg'),
(45, 'Huxley', 'Aldous', 'Aldous Leonard Huxley was an English author, philosopher, and satirist born on July 26, 1894, in Godalming, Surrey, England. He came from a distinguished family of scientists and intellectuals, and his early life was marked by the personal tragedy of losing his sight temporarily as a teenager. Huxley studied English literature at Balliol College, Oxford, and began his career writing poetry and criticism before turning to novels. His masterpiece, Brave New World, published in 1932, is one of the most important dystopian novels ever written, depicting a technologically advanced society where humans are genetically engineered and conditioned for contentment at the cost of freedom, individuality, and authentic experience. The novel remains profoundly relevant as a warning about consumerism, technology, and the manipulation of human happiness. Huxley later became deeply interested in mysticism, parapsychology, and psychedelic substances, writing the influential nonfiction work The Doors of Perception. He died on November 22, 1963.', 'Dead', '1894-07-26', 'author-45-aldous-huxley.jpg'),
(46, 'Monk Kidd', 'Sue', 'Sue Monk Kidd is an American author born on August 12, 1948, in Sylvester, Georgia. She began her writing career as a contributor to religious publications and wrote several spiritual memoirs before turning to fiction. Her debut novel, The Secret Life of Bees, published in 2002, tells the story of a young white girl named Lily Owens who, while fleeing her abusive father in 1964 South Carolina, finds refuge with three Black beekeeping sisters. The novel is a rich exploration of race, grief, mother-daughter relationships, and the female divine. It became a major bestseller and was adapted into a film in 2008. Monk Kidd\'s second novel, The Mermaid Chair, also became a bestseller. Her third novel, The Invention of Wings, published in 2014, tells the story of Sarah Grimké, a real-life abolitionist and feminist of the nineteenth century. The novel was selected for Oprah\'s Book Club and became another major success.', 'Alive', '1948-08-12', 'author-46-sue-monk-kidd.jpg'),
(47, 'Twain', 'Mark', 'Mark Twain was the pen name of Samuel Langhorne Clemens, an American author and humorist born on November 30, 1835, in Florida, Missouri. He is widely considered the father of American literature, and his two masterworks, The Adventures of Tom Sawyer and Adventures of Huckleberry Finn, are cornerstones of the American literary canon. Twain grew up in Hannibal, Missouri, on the banks of the Mississippi River, which became a central setting in his fiction. He worked as a printer, riverboat pilot, and journalist before achieving fame as a writer and lecturer. His writing is characterized by sharp satirical wit, rich vernacular dialogue, and a willingness to confront the hypocrisy and injustice of American society, particularly regarding race and slavery. Adventures of Huckleberry Finn is both celebrated as a masterpiece of realism and debated for its use of racial language. Twain was also a shrewd, though often unlucky, businessman. He died on April 21, 1910.', 'Dead', '1835-11-30', 'author-47-mark-twain.jpg'),
(48, 'Seelye', 'John', 'John Seelye is an American literary critic and scholar born in 1931, known for his expertise in American literature, particularly works of the nineteenth century. He has written extensively on authors including Mark Twain, Herman Melville, and James Fenimore Cooper, and has contributed important critical analyses of the American literary tradition. Seelye also wrote his own creative reimagining of Mark Twain\'s Huck Finn story. His academic career spans several decades, during which he has been an influential voice in the study and interpretation of classic American texts.', 'Dead', '1931-01-01', 'author-48-john-seelye.jpg'),
(49, 'Cardwell', 'Guy', 'Guy Cardwell was an American literary scholar born in 1905, known for his academic work on American literature and his contributions to the study of writers such as Mark Twain. He contributed scholarly essays, critical analyses, and edited volumes that helped shape the academic reception of nineteenth-century American literature. Cardwell was a respected figure in American literary criticism during the mid-twentieth century.', 'Dead', '1905-01-01', 'author-49-guy-cardwell.jpg'),
(50, 'White', 'E.B.', 'Elwyn Brooks White was an American author and essayist born on July 11, 1899, in Mount Vernon, New York. He is best known for his beloved children\'s books, including Stuart Little, Charlotte\'s Web, and The Trumpet of the Swan. Charlotte\'s Web, published in 1952 and illustrated by Garth Williams, is the story of the friendship between a pig named Wilbur and a spider named Charlotte, and is considered one of the greatest children\'s books ever written, touching on themes of friendship, sacrifice, and the cycle of life. White was also a longtime contributor to The New Yorker magazine and is the co-author of The Elements of Style, the influential guide to English writing still widely used today. He was awarded the Presidential Medal of Freedom in 1963 and a special Pulitzer Prize in 1978. White passed away on October 1, 1985.', 'Dead', '1899-07-11', 'author-50-eb-white.jpg'),
(51, 'Williams', 'Garth', 'Garth Williams was an American illustrator born on April 16, 1912, in New York City, who grew up in England and New Jersey. He is one of the most beloved illustrators in the history of children\'s literature, best known for his artwork in E.B. White\'s Charlotte\'s Web and Stuart Little, as well as the original illustrations for Laura Ingalls Wilder\'s Little House series and Margaret Wise Brown\'s Bedtime for Frances. Williams studied at the Royal College of Art in London and began his illustration career in the 1940s. His illustrations are characterized by their warmth, expressiveness, and extraordinary ability to convey personality and emotion through animal characters. Williams worked continuously as an illustrator for decades and illustrated dozens of books for children. He passed away on May 8, 1996.', 'Dead', '1912-04-16', 'author-51-garth-williams.jpg'),
(52, 'Wells', 'Rosemary', 'Rosemary Wells is an American author and illustrator of children\'s books born on January 29, 1943, in New York City. She is best known for creating the beloved characters Max and Ruby, two bunny siblings whose gentle adventures have captivated young readers and been adapted into a popular animated television series. Wells studied at the Museum School of Fine Arts in Boston and worked as a book designer before establishing herself as one of the most prolific and celebrated creators of picture books in the United States. Her books are known for their warmth, humor, and ability to depict the small but significant moments of early childhood. Wells has written and illustrated dozens of books over a career spanning more than five decades and has received numerous awards for her contributions to children\'s literature.', 'Alive', '1943-01-29', 'author-52-rosemary-wells.jpg');
INSERT INTO `auteur` (`idAuteur`, `nom`, `prenom`, `description`, `status`, `dateNaiss`, `image`) VALUES
(53, 'Haddon', 'Mark', 'Mark Haddon is a British author, poet, and illustrator born on September 26, 1962, in Northampton, England. He studied English literature at Merton College, Oxford, and worked extensively as a screenwriter and illustrator before publishing his breakthrough novel. The Curious Incident of the Dog in the Night-Time, published in 2003, is narrated by fifteen-year-old Christopher Boone, who has behavioral difficulties consistent with autism or Asperger syndrome, and who investigates the death of a neighbor\'s dog. The novel was a publishing sensation, winning the Whitbread Award for both Novel and Book of the Year, selling millions of copies worldwide, and being adapted into a hugely successful stage production that won seven Olivier Awards. Haddon has also published poetry, other novels for adults and children, and has continued to work across multiple creative disciplines.', 'Alive', '1962-09-26', 'author-53-mark-haddon.jpg'),
(54, 'Hawkins', 'Paula', 'Paula Hawkins is a British author born on August 26, 1972, in Harare, Zimbabwe, who grew up in Zimbabwe before moving to London at the age of seventeen. She studied philosophy, politics, and economics at Oxford University and worked for fifteen years as a financial journalist before turning to fiction. Hawkins first published four romantic comedies under the pen name Amy Silver, but it was her psychological thriller The Girl on the Train, published in 2015, that catapulted her to international fame. The novel, which follows an alcoholic woman who becomes obsessed with a couple she sees from her commuter train, became a massive global bestseller, selling over twenty million copies and being translated into more than forty languages. It was adapted into a major Hollywood film in 2016. Hawkins\'s work is praised for its complex female narrators, unreliable perspectives, and tightly plotted suspense.', 'Alive', '1972-08-26', 'author-54-paula-hawkins.jpg'),
(55, 'Pullman', 'Philip', 'Philip Pullman is a British author born on October 19, 1946, in Norwich, England. He studied English at Exeter College, Oxford, and worked as a teacher for many years before becoming a full-time writer. Pullman is best known for his His Dark Materials trilogy, consisting of Northern Lights (published as The Golden Compass in the United States), The Subtle Knife, and The Amber Spyglass. The series, set in parallel universes and featuring a young girl named Lyra Belacqua, is a sweeping epic that engages with themes of free will, the nature of consciousness, religion, and the loss of innocence. The Amber Spyglass became the first children\'s book to win the prestigious Whitbread Book of the Year Award. The trilogy has been adapted into a film and a critically acclaimed BBC television series. Pullman is also known for his outspoken atheism and his criticisms of organized religion.', 'Alive', '1946-10-19', 'author-55-philip-pullman.jpg'),
(56, 'Brontë', 'Emily', 'Emily Jane Brontë was an English novelist and poet born on July 30, 1818, in Thornton, Yorkshire, England. She was the middle Brontë sister, between Charlotte and Anne, and is remembered as one of the most distinctive voices in English literature. Emily spent most of her life on the Yorkshire moors, venturing away only reluctantly, and the wild, rugged landscape deeply influenced her imagination. She published her only novel, Wuthering Heights, in 1847 under the pseudonym Ellis Bell, alongside her sisters\' novels. The book tells the passionate and destructive love story of Heathcliff and Catherine Earnshaw against the bleak Yorkshire moorland and is considered a masterwork of Gothic fiction. Wuthering Heights received mixed reviews upon publication but is now recognized as a classic that transcends its genre. Emily also wrote poetry of striking originality and power. She died of tuberculosis on December 19, 1848, at the age of thirty.', 'Dead', '1818-07-30', 'author-56-emily-brontë.jpg'),
(57, 'J. Dunn', 'Richard', 'Richard J. Dunn is an American literary scholar known for his academic work on Victorian literature, particularly on the novels of Charles Dickens. He has written and edited critical studies and editions of Dickens\'s work, helping to advance scholarly understanding of Dickens\'s narrative techniques, social themes, and cultural significance. His editorial and critical contributions have been valuable resources for students and scholars of Victorian fiction.', 'Alive', '1938-01-01', 'author-57-richard-j-dunn.jpg'),
(58, 'Picoult', 'Jodi', 'Jodi Picoult is an American author born on May 19, 1966, in Nesconset, New York. She studied creative writing at Princeton University and later earned a master\'s degree in education from Harvard University. Picoult has written over twenty-five novels, most of which center on moral and ethical dilemmas explored through multiple narrative perspectives, often examining difficult topics such as genetic ethics, school shootings, racial injustice, and family crises. Her breakthrough novel My Sister\'s Keeper, published in 2004, tells the story of a girl suing her parents for the rights to her own body after being conceived specifically to be a donor for her ill sister. The novel was adapted into a film in 2009. Picoult is one of the most commercially successful literary fiction writers in the United States and is known for her thorough research and ability to present complex issues with empathy and nuance.', 'Alive', '1966-05-19', 'author-58-jodi-picoult.jpg'),
(59, 'Vonnegut Jr.', 'Kurt', 'Kurt Vonnegut Jr. was an American author born on November 11, 1922, in Indianapolis, Indiana. He is one of the most influential American writers of the twentieth century, known for blending satire, dark humor, and science fiction to explore the absurdities of human existence and the horrors of war. Vonnegut was captured by German forces during the Battle of the Bulge and survived the firebombing of Dresden while a prisoner of war, sheltering in an underground slaughterhouse. This experience became the central event of his most celebrated novel, Slaughterhouse-Five, published in 1969, which blends the autobiographical with science fiction through the character of Billy Pilgrim, who becomes unstuck in time. Vonnegut studied biochemistry at Cornell University and anthropology at the University of Chicago. His other notable works include Cat\'s Cradle, Breakfast of Champions, and The Sirens of Titan. He passed away on April 11, 2007.', 'Dead', '1922-11-11', 'author-59-kurt-vonnegut-jr.jpg'),
(60, 'Mitchell', 'Margaret', 'Margaret Munnerlyn Mitchell was an American novelist born on November 8, 1900, in Atlanta, Georgia. She is known for a single novel, Gone with the Wind, published in 1936, which became one of the most popular novels of all time and won the Pulitzer Prize for Fiction in 1937. The novel is set in the American South during the Civil War and Reconstruction era and centers on the willful, resourceful Scarlett O\'Hara as she navigates love, loss, and survival. Mitchell worked as a journalist for the Atlanta Journal before writing the novel during a convalescence. Gone with the Wind sold a million copies in its first year and the 1939 film adaptation starring Clark Gable and Vivien Leigh won eight Academy Awards. Mitchell was a private person who wrote no further novels. She died after being struck by a car on August 16, 1949.', 'Dead', '1900-11-08', 'author-60-margaret-mitchell.jpg'),
(61, 'Chbosky', 'Stephen', 'Stephen Chbosky is an American novelist, screenwriter, and film director born in 1970 in Pittsburgh, Pennsylvania. He studied screenwriting and directing at the University of Southern California\'s film school. His debut novel, The Perks of Being a Wallflower, published in 1999, tells the story of Charlie, a sensitive and introverted freshman navigating high school while dealing with trauma, mental illness, and the complexities of friendship and first love. The novel became a cult classic, particularly among teenagers, and has sold millions of copies worldwide. It is also one of the most frequently challenged and banned books in American schools. Chbosky directed the 2012 film adaptation of the novel himself, with the cast including Logan Lerman, Emma Watson, and Ezra Miller. He has also written the screenplays for other major film productions, including the live-action Beauty and the Beast.', 'Alive', '1970-01-25', 'author-61-stephen-chbosky.jpg'),
(62, 'Scott Card', 'Orson', 'Orson Scott Card is an American science fiction author born on August 24, 1951, in Richland, Washington. He is best known for his novel Ender\'s Game, published in 1985, which won both the Hugo Award and the Nebula Award, as did its sequel Speaker for the Dead, making Card the only author to win both awards in consecutive years. Ender\'s Game follows the child prodigy Andrew Ender Wiggin, who is trained from a young age to lead Earth\'s military forces against an alien race. The novel is celebrated for its psychological depth, moral complexity, and its thoughtful exploration of empathy and warfare. Card is a member of The Church of Jesus Christ of Latter-day Saints, and his faith influences much of his writing and worldview. He has been a prolific author across multiple genres, and Ender\'s Game was adapted into a film in 2013.', 'Alive', '1951-08-24', 'author-62-orson-scott-card.jpg'),
(63, 'King', 'Stephen', 'Stephen Edwin King is an American author born on September 21, 1947, in Portland, Maine. He is one of the most prolific and successful authors in the history of popular fiction, having published over sixty novels and two hundred short stories across the genres of horror, supernatural fiction, suspense, and fantasy. King studied English at the University of Maine and worked as a schoolteacher while struggling to get published. His debut novel Carrie, the story of a telekinetic girl who wreaks revenge on her tormentors, was first published in 1974 after his wife retrieved it from the trash where he had thrown it in frustration. It launched one of the most remarkable careers in modern literature. King\'s works, including The Shining, It, Misery, and The Stand, have sold over 350 million copies worldwide and many have been adapted into major films and television series. He has received numerous awards, including the National Medal of Arts.', 'Alive', '1947-09-21', 'author-63-stephen-king.jpg'),
(64, 'Fielding', 'Helen', 'Helen Fielding is a British author and journalist born on February 19, 1958, in Morley, West Yorkshire, England. She studied English literature at St Anne\'s College, Oxford, and worked as a journalist and television producer before turning to fiction. Fielding created the character of Bridget Jones in a newspaper column for The Independent, inspired partly by Jane Austen\'s Pride and Prejudice. Bridget Jones\'s Diary, published as a novel in 1996, is a comedic first-person diary about a single woman in her thirties navigating modern love, career, and self-improvement. The novel was a massive international bestseller and helped define the chick lit genre of the 1990s and 2000s. It was adapted into a hugely popular film in 2001 starring Renée Zellweger, and spawned multiple sequels in both book and film form. Fielding\'s work is celebrated for its warmth, self-deprecating humor, and its honest portrayal of female insecurities and aspirations.', 'Alive', '1958-02-19', 'author-64-helen-fielding.jpg'),
(65, 'Tanner', 'Tony', 'Tony Tanner was a British literary critic and academic born in 1935, known particularly for his influential scholarship on American literature and the work of Henry James. He was a professor at King\'s College, Cambridge, where he taught for many years and was regarded as one of the most brilliant and charismatic literary scholars of his generation. Tanner\'s major works include City of Words, a landmark study of American fiction, and his extensive writings on Jane Austen and Henry James. His critical approach combined close textual reading with broad cultural and philosophical insight, and he inspired generations of students and fellow scholars. Tanner passed away in 1998.', 'Dead', '1935-01-01', 'author-65-tony-tanner.jpg'),
(66, 'Ballaster', 'Ros', 'Ros Ballaster is a British literary scholar and academic known for her research in eighteenth-century British literature, women\'s writing, and the history of the novel. She is a professor at Mansfield College, University of Oxford. Her scholarly work includes important studies on women\'s popular fiction, the history of romance, and early modern literary culture. Ballaster has edited and introduced numerous editions of classic literary texts and has contributed significantly to the academic understanding of gender, narrative, and the development of the English novel.', 'Alive', '1964-01-01', 'author-66-ros-ballaster.jpg'),
(67, 'Sachar', 'Louis', 'Louis Sachar is an American author of children\'s books born on March 20, 1954, in East Meadow, New York. He studied economics at the University of California, Berkeley, where he volunteered at a local elementary school as a teacher\'s aide, an experience that inspired his first series of books featuring Sideways School. Sachar later attended Hastings College of the Law and worked briefly as a lawyer before pursuing writing full time. His novel Holes, published in 1998, is the story of a boy named Stanley Yelnats who is wrongly convicted of theft and sent to a juvenile detention camp where the warden forces the boys to dig holes in a dry lake bed. The novel won the Newbery Medal and the National Book Award, and was adapted into a successful Disney film in 2003. Sachar is celebrated for his inventive plotting, dry humor, and his ability to connect with young readers.', 'Alive', '1954-03-20', 'author-67-louis-sachar.jpg'),
(68, 'Weisberger', 'Lauren', 'Lauren Weisberger is an American author born on March 28, 1977, in Scranton, Pennsylvania. She studied English literature at Cornell University and, after graduating, worked as an assistant to Anna Wintour, the editor-in-chief of Vogue magazine. Her experiences in that role inspired her debut novel, The Devil Wears Prada, published in 2003. The novel, which tells the story of a young woman working as an assistant for a tyrannical fashion magazine editor, became a major bestseller and was adapted into a hugely popular film starring Meryl Streep and Anne Hathaway in 2006. Weisberger has since written several other novels, including Everyone Worth Knowing and Revenge Wears Prada. Her work is known for its insider knowledge of the fashion and media industries and its sharp satirical wit.', 'Alive', '1977-03-28', 'author-68-lauren-weisberger.jpg'),
(69, 'Homer', NULL, 'Homer is the presumed ancient Greek author credited with composing the Iliad and the Odyssey, two of the foundational works of Western literature. The exact identity and historical existence of Homer has been debated by scholars for centuries in what is known as the Homeric Question. Most modern scholars believe the epics were composed in the eighth or seventh century BCE, drawing on an oral tradition stretching back to the Mycenaean period. The Iliad recounts events during the Trojan War, focusing on the warrior Achilles, while the Odyssey follows the hero Odysseus on his ten-year journey home after the fall of Troy. These two epics established many of the conventions of Western epic poetry, storytelling, and the depiction of heroism and the human condition. Homer\'s works have been continuously read, translated, adapted, and studied for nearly three thousand years and remain essential touchstones of world literature.', 'Dead', NULL, 'author-69-homer.jpg'),
(70, 'Fagles', 'Robert', 'Robert Fagles was an American poet and translator born on September 11, 1933, in Philadelphia, Pennsylvania. He is widely regarded as one of the greatest translators of ancient Greek literature into English. His translations of Homer\'s Iliad and Odyssey, and of Sophocles\' Theban plays, are celebrated for capturing the energy, beauty, and emotional power of the original Greek texts in vivid and accessible contemporary English. Fagles was a professor of comparative literature at Princeton University for many years, where he was beloved by students and colleagues alike. His translation of the Iliad, published in 1990, and his Odyssey, published in 1996, both became bestsellers and are widely used in universities worldwide. He received numerous honors for his contributions to literature and translation. Fagles passed away on March 26, 2008.', 'Dead', '1933-09-11', 'author-70-robert-fagles.jpg'),
(71, 'Rieu', 'E.V.', 'Emile Victor Rieu was a British classical scholar, editor, and translator born on February 10, 1887. He is best known for his translations of Homer\'s Iliad and Odyssey into plain English prose for the Penguin Classics series, which he also founded and edited. Rieu\'s translation of the Odyssey, published in 1946 as the very first Penguin Classic, sold over three million copies and brought Homer to a mass audience who might have found more formal translations forbidding. His goal was always to make the great works of antiquity accessible and enjoyable to the ordinary reader, and his translations remain beloved for their readability and vitality. Rieu passed away on May 11, 1972.', 'Dead', '1887-02-08', 'author-71-ev-rieu.jpg'),
(72, 'de Saint-Exupéry', 'Antoine', 'Antoine Marie Jean-Baptiste Roger, comte de Saint-Exupéry was a French writer, poet, and pioneering aviator born on June 29, 1900, in Lyon, France. He worked as a mail pilot in Africa and South America, experiences that informed his aviation memoirs Night Flight and Wind, Sand and Stars. His most celebrated work, Le Petit Prince (The Little Prince), was published in 1943 and is one of the most translated and best-selling books in history, with over 200 million copies sold worldwide. The deceptively simple story of a young prince from a tiny asteroid explores themes of loneliness, love, friendship, and the loss of innocence in ways that resonate deeply with both children and adults. Saint-Exupéry disappeared on July 31, 1944, while on a reconnaissance mission during World War II. His plane was eventually found decades later in the Mediterranean, but the mystery of his fate long fueled speculation and legend.', 'Dead', '1900-06-29', 'author-72-antoine-de-saint-exupéry.jpg'),
(73, 'Howard', 'Richard', 'Richard Howard is an American poet, literary critic, and translator born on October 13, 1929, in Cleveland, Ohio. He is one of the most distinguished American translators of French literature, having translated over 150 works from French into English, including works by Roland Barthes, André Gide, Charles de Gaulle, and many others. Howard was awarded the Pulitzer Prize for Poetry in 1970 for his collection Untitled Subjects. He is also known as a poetry editor and has been a crucial figure in championing American poetry for decades. As a translator, his work is praised for its elegance, fidelity to the original, and sensitivity to literary style.', 'Alive', '1929-10-13', 'author-73-richard-howard.jpg'),
(74, 'Marcos Barbosa', 'Dom', 'Dom Marcos Barbosa was a Brazilian Benedictine monk, poet, and translator. He is known in Brazil for his literary work and his translations of classic texts into Portuguese. As a monk at the São Bento Abbey in Rio de Janeiro, he combined religious life with a distinguished literary career, contributing to Brazilian Catholic cultural life and letters. His translation work helped make important works of world literature accessible to Portuguese-speaking readers.', 'Dead', '1915-09-12', 'author-74-dom-marcos-barbosa.jpg'),
(75, 'Walls', 'Jeannette', 'Jeannette Walls is an American author and journalist born on April 21, 1960, in Phoenix, Arizona. She grew up in a deeply unconventional family led by her father Rex Walls, a charismatic, brilliant, but deeply troubled alcoholic, and her artistic but neglectful mother. The family moved frequently, often living in poverty and sometimes in homelessness. Walls worked her way out of her impoverished circumstances and became a successful New York journalist and gossip columnist for New York magazine. Her memoir The Glass Castle, published in 2005, tells the story of her extraordinary and difficult childhood with unflinching honesty and remarkable lack of bitterness. The book became a phenomenon, spending over six years on the New York Times bestseller list and selling millions of copies worldwide. It was adapted into a film in 2017. Walls also wrote the novel Half Broke Horses, based on the life of her grandmother.', 'Alive', '1960-04-21', 'author-75-jeannette-walls.jpg'),
(76, 'Krakauer', 'Jon', 'Jon Krakauer is an American author and journalist born on April 12, 1954, in Brookline, Massachusetts. He is known for writing nonfiction books that blend outdoor adventure narrative with investigative journalism and social commentary. Krakauer was an experienced mountain climber and in 1996 joined an expedition to climb Mount Everest. He witnessed and survived the catastrophic 1996 Everest disaster, in which a sudden storm killed eight climbers. His account of the experience, Into Thin Air, published in 1997, became one of the bestselling nonfiction books of the decade and sparked significant debate about commercialized mountaineering. His other major works include Into the Wild, the investigation of the death of Christopher McCandless in the Alaskan wilderness, and Under the Banner of Heaven, an examination of fundamentalist Mormon violence. Krakauer\'s writing is noted for its gripping narrative style and moral seriousness.', 'Alive', '1954-04-12', 'author-76-jon-krakauer.jpg'),
(77, 'Dickens', 'Charles', 'Charles John Huffam Dickens was an English novelist and social critic born on February 7, 1812, in Portsmouth, Hampshire, England. He is widely regarded as the greatest novelist of the Victorian era and one of the most influential writers in the history of the English language. Dickens\'s childhood was marked by hardship: his father was imprisoned for debt, and young Charles was forced to work in a boot-blacking factory, experiences that profoundly shaped his social conscience and his depictions of poverty, injustice, and childhood suffering. He began his career as a journalist and rose to literary fame with The Pickwick Papers. His major works include Oliver Twist, A Tale of Two Cities, Great Expectations, David Copperfield, and A Christmas Carol, the last of which transformed Western traditions around the Christmas holiday. Dickens was also a passionate social reformer who used his fame to advocate for the poor and the reform of social institutions. He passed away on June 9, 1870.', 'Dead', '1812-02-07', 'author-77-charles-dickens.jpg'),
(78, 'Maxwell', 'Richard', 'Richard Maxwell is an academic and author known for his work in the fields of media studies, environmental humanities, and cultural theory. He has written and edited works examining the environmental impact of media technologies and the relationship between media, ecology, and culture. His scholarship engages with questions of sustainability, labor, and the material conditions of media production and consumption.', 'Alive', '1948-01-01', 'author-78-richard-maxwell.jpg'),
(79, 'Knight Browne', 'Hablot', 'Hablot Knight Browne, known by his pen name Phiz, was a British artist and illustrator born on June 15, 1815, in Kennington, Surrey, England. He is best known as the principal illustrator of Charles Dickens\'s novels for nearly two decades, beginning with The Pickwick Papers after the original illustrator died. Browne created the visual identity of many of Dickens\'s most beloved characters, including Sam Weller, Uriah Heep, and Mr. Micawber. His intricate etchings and drawings perfectly complemented Dickens\'s style and became an integral part of how Victorian readers experienced the novels. Browne illustrated many of Dickens\'s major works, including Nicholas Nickleby, Dombey and Son, David Copperfield, Bleak House, Little Dorrit, and A Tale of Two Cities. He suffered a stroke in 1867 that severely limited his ability to draw, and he died on July 8, 1882.', 'Dead', '1815-06-15', 'author-79-hablot-knight-browne.jpg'),
(80, 'Grisham', 'John', 'John Grisham is an American author and former attorney born on February 8, 1955, in Jonesboro, Arkansas. He studied accounting and then law, graduating from the University of Mississippi School of Law. He worked as a criminal defense attorney and served in the Mississippi House of Representatives before turning to writing. Grisham spent three years writing his debut legal thriller A Time to Kill, which was rejected by many publishers and initially printed in a small run. His second novel, The Firm, became a massive bestseller and launched one of the most successful careers in commercial fiction. Grisham has since published over forty novels, most of them legal thrillers set in the American South, and has sold over 300 million copies worldwide. He is one of only three authors to have sold two million copies of a book in a first printing. Many of his novels have been adapted into major Hollywood films.', 'Alive', '1955-02-08', 'author-80-john-grisham.jpg'),
(81, 'Wiesel', 'Elie', 'Eliezer Wiesel was a Romanian-born Jewish-American author, professor, political activist, Nobel laureate, and Holocaust survivor born on September 30, 1928, in Sighet, in what is now Romania. At the age of fifteen, Wiesel and his family were deported to Auschwitz, and then to Buchenwald. His mother and younger sister were killed upon arrival at Auschwitz, and his father died of starvation and dysentery at Buchenwald shortly before liberation. Wiesel\'s seminal memoir Night, published in French in 1958, is a searing testimony of his experiences in the Nazi death camps and is considered one of the most important works of Holocaust literature. He later settled in the United States, becoming a citizen in 1963, and devoted his life to speaking and writing on behalf of Holocaust remembrance, human rights, and the fight against indifference to suffering. Wiesel was awarded the Nobel Peace Prize in 1986. He passed away on July 2, 2016.', 'Dead', '1928-09-30', 'author-81-elie-wiesel.jpg'),
(82, 'Wiesel', 'Marion', 'Marion Wiesel is the wife of Holocaust survivor and Nobel laureate Elie Wiesel, and is herself a noted translator. Born in 1931, she translated her husband\'s most celebrated work, Night, from the French into a new English translation published by Hill and Wang in 2006. This revised translation replaced an earlier English version and was widely praised for its greater fidelity to the original text and its more immediate emotional power. Marion Wiesel has also been deeply involved in the Elie Wiesel Foundation for Humanity and has supported his work in Holocaust remembrance and human rights advocacy throughout their marriage.', 'Alive', '1931-01-01', 'author-82-marion-wiesel.jpg'),
(83, 'Goldman', 'William', 'William Goldman was an American novelist, playwright, and screenwriter born on August 12, 1931, in Highland Park, Illinois. He is regarded as one of the greatest screenwriters in Hollywood history, having written the screenplays for Butch Cassidy and the Sundance Kid, for which he won his first Academy Award, and All the President\'s Men, for which he won his second. He also wrote the screenplay for the beloved fantasy adventure The Princess Bride, adapting his own 1973 novel of the same name. Goldman\'s book Adventures in the Screen Trade is considered an essential work about the film industry, coining the famous phrase \'Nobody knows anything\' about Hollywood\'s inability to predict success. As a novelist, The Princess Bride remains his most popular work, combining fairy tale romance, swashbuckling adventure, and sharp comedy. Goldman passed away on November 16, 2018.', 'Dead', '1931-08-12', 'author-83-william-goldman.jpg'),
(84, 'Hinton', 'S.E.', 'Susan Eloise Hinton is an American author born on July 22, 1950, in Tulsa, Oklahoma. She is best known for her debut novel The Outsiders, which she wrote when she was just fifteen years old and published at the age of eighteen in 1967. The novel, written from the perspective of a poor teenage boy named Ponyboy Curtis and his conflict with a wealthier gang, captured the authentic voices and struggles of American youth in a way that resonated deeply with readers. Because publishers feared a book about gang violence would not be taken seriously from a female author, she published under her initials S.E. Hinton. The Outsiders was a landmark in young adult literature, helping to establish the genre as a legitimate and important category of fiction. It has sold over 14 million copies and was adapted into a celebrated 1983 film directed by Francis Ford Coppola. Hinton wrote several other acclaimed novels for young readers, including That Was Then, This Is Now and Rumble Fish.', 'Alive', '1948-07-22', 'author-84-se-hinton.jpg'),
(85, 'Dashner', 'James', 'James Dashner is an American author born on November 26, 1972, in Austell, Georgia. He studied accounting at Brigham Young University before pursuing a career as a writer. Dashner is best known for The Maze Runner series, a young adult science fiction saga that begins with a group of teenage boys who wake up with no memories in a glade surrounded by a massive, ever-changing maze. The series, which grew to five books including prequels, became a major international bestseller and was adapted into a successful film franchise. Dashner\'s writing is known for its breakneck pacing, high-concept premises, and ability to keep readers turning pages. He has also written other young adult fantasy and science fiction series, including The 13th Reality and The Mortality Doctrine.', 'Alive', '1972-11-26', 'author-85-james-dashner.jpg'),
(86, 'D. Levitt', 'Steven', 'Steven David Levitt is an American economist born on May 29, 1967, in Minneapolis, Minnesota. He is a professor of economics at the University of Chicago and is known for his work applying economic theory and statistical analysis to unconventional real-world topics. Levitt received the John Bates Clark Medal in 2003, awarded to the American economist under forty who has made the most significant contribution to the field. He is perhaps best known to the general public as the co-author, with journalist Stephen J. Dubner, of Freakonomics, published in 2005. The book explores the hidden side of everything, applying economic thinking to topics as diverse as the economics of drug dealing, the impact of parents\' choices on children\'s success, and the reasons crime fell in the 1990s. The book became a massive bestseller and spawned a franchise including sequels, a documentary film, and a popular podcast.', 'Alive', '1967-05-29', 'author-86-steven-d-levitt.jpg'),
(87, 'J. Dubner', 'Stephen', 'Stephen J. Dubner is an American journalist, author, and radio and television personality known for his work co-authoring the Freakonomics series with economist Steven D. Levitt. Dubner grew up in the Catskill Mountains of New York, the youngest of eight children of parents who had converted from Judaism to Roman Catholicism. He studied at Appalachian State University and Columbia University and worked as a journalist for The New York Times Magazine and other publications. His collaboration with Levitt on Freakonomics, published in 2005, was a global phenomenon, bringing economic analysis of surprising topics to a mass audience. Dubner has hosted the successful Freakonomics Radio podcast, which has millions of listeners worldwide. He has also written several books independently, including a memoir about his exploration of his family\'s religious identity.', 'Alive', '1963-08-26', 'author-87-stephen-j-dubner.jpg'),
(88, 'Hodgson Burnett', 'Frances', 'Frances Eliza Hodgson Burnett was a British-American author born on November 24, 1849, in Cheetham, Manchester, England. She emigrated with her family to the United States after her father\'s death left the family in poverty. Burnett became a prolific and successful novelist, but she is best remembered today for three beloved children\'s classics: Little Lord Fauntleroy, published in 1886; A Little Princess, published in 1905; and The Secret Garden, published in 1911. The Secret Garden, which tells the story of a spoiled orphan girl who discovers a hidden, overgrown garden on the Yorkshire moors and is transformed by tending to it, has become one of the most enduringly beloved works of children\'s literature, celebrated for its themes of renewal, healing, and the transformative power of nature. Burnett was also a celebrated figure in society on both sides of the Atlantic. She died on October 29, 1924.', 'Dead', '1849-11-24', 'author-88-frances-hodgson-burnett.jpg'),
(89, 'García Márquez', 'Gabriel', 'Gabriel José de la Concordia García Márquez was a Colombian novelist, short-story writer, screenwriter, and journalist born on March 6, 1927, in Aracataca, Colombia. He is one of the most significant authors of the twentieth century and a key figure in the Latin American literary boom of the 1960s and 1970s. García Márquez is the founder and supreme practitioner of magical realism, a style in which magical elements are blended seamlessly into realistic narratives. His masterpiece, One Hundred Years of Solitude, published in 1967, traces seven generations of the Buendía family in the mythical town of Macondo and is one of the most important novels ever written. The book sold more than fifty million copies and was a major factor in García Márquez being awarded the Nobel Prize in Literature in 1982. His other celebrated works include Love in the Time of Cholera and The Autumn of the Patriarch. He passed away on April 17, 2014.', 'Dead', '1927-03-06', 'author-89-gabriel-garcía-márquez.jpg'),
(90, 'Rabassa', 'Gregory', 'Gregory Rabassa was an American translator and professor born on March 9, 1922, in Yonkers, New York. He is widely regarded as one of the greatest translators of Spanish and Portuguese literature into English in the twentieth century. Rabassa translated many of the landmark works of the Latin American literary boom, including Gabriel García Márquez\'s One Hundred Years of Solitude and Julio Cortázar\'s Hopscotch. García Márquez famously stated that Rabassa\'s English translation of his novel was better than the Spanish original, one of the highest compliments ever paid to a literary translator. Rabassa was a professor at Queens College, City University of New York, for many years. He received the PEN Medal for Translation and the National Medal of Arts. Rabassa passed away on June 13, 2016.', 'Dead', '1922-03-09', 'author-90-gregory-rabassa.jpg'),
(91, 'Wilde', 'Oscar', 'Oscar Fingal O\'Flahertie Wills Wilde was an Irish poet, playwright, and author born on October 16, 1854, in Dublin, Ireland. He studied classics at Trinity College Dublin and then at Magdalen College, Oxford, where he developed his philosophy of aestheticism and his famously witty, paradoxical style. Wilde became one of the most celebrated literary figures of Victorian London, known as much for his dazzling conversation and flamboyant personality as for his writing. His works include the comic plays The Importance of Being Earnest and An Ideal Husband, the novel The Picture of Dorian Gray, and the fairy tale collections The Happy Prince and Other Stories. In 1895, Wilde was convicted of gross indecency for his relationship with Lord Alfred Douglas and sentenced to two years hard labor, a punishment that destroyed his health and career. He died in poverty in Paris on November 30, 1900, but his literary reputation has only grown with time.', 'Dead', '1854-10-16', 'author-91-oscar-wilde.jpg'),
(92, 'Eugenides', 'Jeffrey', 'Jeffrey Eugenides is an American author born on March 8, 1960, in Detroit, Michigan. He studied English at Brown University and creative writing at Stanford University. Eugenides is a remarkably careful and unhurried writer, having published only three novels in over three decades, each of which has been highly acclaimed. His debut, The Virgin Suicides, published in 1993, tells the mysterious story of five sisters whose suicides are reconstructed years later by the neighborhood boys who were obsessed with them. It was adapted into a film by Sofia Coppola in 1999. His second novel, Middlesex, published in 2002, tells the multigenerational saga of a Greek-American family and the intersex narrator Cal Stephanides, and won the Pulitzer Prize for Fiction. His third novel, The Marriage Plot, was published in 2011. Eugenides is widely admired for his ambitious scope, meticulous prose, and deep literary intelligence.', 'Alive', '1960-03-08', 'author-92-jeffrey-eugenides.jpg'),
(93, 'Stoker', 'Bram', 'Abraham Stoker was an Irish author born on November 8, 1847, in Clontarf, Dublin, Ireland. He spent many years as the business manager for the Lyceum Theatre in London, working closely with the celebrated actor Sir Henry Irving, a demanding and dominant personality who some scholars believe influenced the character of Count Dracula. Stoker wrote several novels and short stories, but he is remembered almost entirely for Dracula, published in 1897. The Gothic horror novel, set partly in Transylvania and partly in England, introduced the vampire Count Dracula and the concept of the modern vampire to the world. Written as a collection of journal entries, letters, and newspaper clippings, it became the defining vampire narrative and one of the most influential horror novels ever written. Stoker passed away on April 20, 1912, and could not have imagined the vast cultural legacy his novel would inspire.', 'Dead', '1847-11-08', 'author-93-bram-stoker.jpg'),
(94, 'Auerbach', 'Nina', 'Nina Auerbach is an American literary scholar and professor known for her significant contributions to the study of Victorian literature, feminism, and vampire mythology in culture. She is a professor at the University of Pennsylvania and the author of several influential academic works, including Communities of Women: An Idea in Fiction and Our Vampires, Ourselves, a cultural study of how vampire mythology has reflected changing social anxieties across different eras. Her scholarship combines feminist criticism with cultural analysis and has been influential in both literary studies and the emerging field of vampire studies.', 'Alive', '1943-01-01', 'author-94-auerbach-nina.jpg'),
(95, 'J. Skal', 'David', 'David J. Skal is an American author and cultural historian born in 1952, known for his expertise on horror film history, the gothic tradition, and vampire mythology in popular culture. He is the author of Hollywood Gothic: The Tangled Web of Dracula from Novel to Stage to Screen and The Monster Show: A Cultural History of Horror, both of which are considered essential works in the field of horror studies. Skal has also written extensively about the life of Bram Stoker and has worked as a documentary filmmaker and commentary writer for horror film releases. His work is known for blending meticulous historical research with accessible, engaging prose.', 'Alive', '1952-01-01', 'author-95-david-j-skal.jpg'),
(96, 'Kingsolver', 'Barbara', 'Barbara Kingsolver is an American novelist, essayist, and poet born on April 8, 1955, in Annapolis, Maryland. She grew up in rural Kentucky and studied biology at DePauw University and the University of Arizona, where she earned a master\'s degree in biology and ecology. Her scientific background strongly informs her writing, particularly her attention to the natural world and environmental themes. Kingsolver worked as a freelance journalist and technical writer before publishing her debut novel The Bean Trees in 1988. Her most celebrated novel, The Poisonwood Bible, published in 1998, follows an American Baptist missionary who takes his family to the Belgian Congo in 1959, and is considered a masterwork of postcolonial fiction and feminist literature. Kingsolver has received numerous awards, including the Pulitzer Prize for Fiction in 2023 for her novel Demon Copperhead. She is also known for her environmental activism and her nonfiction work Animal, Vegetable, Miracle.', 'Alive', '1955-04-08', 'author-96-barbara-kingsolver.jpg'),
(97, 'Sedaris', 'David', 'David Sedaris is an American humorist, writer, and radio contributor born on December 26, 1956, in Binghamton, New York. He grew up in Raleigh, North Carolina, and later studied writing at the School of the Art Institute of Chicago. His literary career was launched when he read a passage from his diary on a Chicago radio program hosted by Ira Glass, who recognized his unique comic voice and broadcast it on This American Life. His debut collection Barrel Fever, published in 1994, was followed by the enormously successful Naked and Me Talk Pretty One Day, which brought him widespread fame for his sharp, self-deprecating humor and his hilarious and touching accounts of his dysfunctional family, his struggles with obsessive-compulsive disorder, and his experiences as an expatriate living in France. Sedaris is a beloved figure in American literature and a frequent contributor to The New Yorker and NPR.', 'Alive', '1956-12-26', 'author-97-david-sedaris.jpg'),
(98, 'Sendak', 'Maurice', 'Maurice Bernard Sendak was an American author and illustrator of children\'s books born on June 10, 1928, in Brooklyn, New York, to Polish-Jewish immigrants. He is widely considered the most important creator in the history of children\'s picture books. Sendak began his career illustrating other authors\' books before writing and illustrating his own. His masterpiece, Where the Wild Things Are, published in 1963, tells the story of a misbehaving boy named Max who is sent to bed and imagines a voyage to the land of the Wild Things, where he becomes their king. The book revolutionized children\'s literature by taking children\'s anger, imagination, and inner life seriously, acknowledging the complex emotional worlds of young people. It won the Caldecott Medal in 1964. Sendak was also a set and costume designer for opera and theater. He passed away on May 8, 2012.', 'Dead', '1928-06-10', 'author-98-maurice-sendak.jpg'),
(99, 'Dumas', 'Alexandre', 'Alexandre Dumas was a French author born on July 24, 1802, in Villers-Cotterêts, France. He is one of the most widely read French authors in the world, known for his exciting historical adventure novels that were originally published as serials. Dumas was of mixed French and Haitian descent, and his grandfather was an enslaved man from Saint-Domingue. His most celebrated works include The Three Musketeers, published in 1844, and The Count of Monte Cristo, published between 1844 and 1846. These novels, with their memorable characters, elaborate plots, and thrilling action, have been adapted into films, television series, and stage productions countless times. Dumas was extraordinarily prolific, writing hundreds of novels and plays, often collaborating with assistants, and he was at one point the most widely read French author in the world. Despite his enormous earnings, he was frequently in financial difficulty due to his extravagant lifestyle. He died on December 5, 1870.', 'Dead', '1802-07-24', 'author-99-alexandre-dumas.jpg'),
(100, 'Buss', 'Robin', 'Robin Buss is a British translator and writer known for his translations of French literature into English for Penguin Classics, including works by Alexandre Dumas and other major figures of French literature. His translations are praised for their readability and fidelity to the spirit and style of the originals. Buss has contributed to making important works of French literature accessible to English-speaking readers, and his careful, scholarly approach to translation has earned him a respected place among literary translators.', 'Alive', '1939-01-01', 'author-100-robin-buss.jpg'),
(101, 'McCarthy', 'Cormac', 'Cormac McCarthy was an American author born on July 20, 1933, in Providence, Rhode Island, who grew up in Knoxville, Tennessee. He studied at the University of Tennessee but left without a degree. McCarthy is considered one of the greatest American novelists of the twentieth and early twenty-first centuries, known for his spare, Faulknerian prose, biblical cadences, and unsparing portrayals of violence and the human capacity for both savagery and grace. His major works include Blood Meridian, the Border Trilogy, No Country for Old Men, and The Road. The Road, published in 2006, follows a father and son traveling through a post-apocalyptic American landscape and won the Pulitzer Prize for Fiction in 2007. It was adapted into a film in 2009. No Country for Old Men was also adapted into a film by the Coen Brothers that won the Academy Award for Best Picture. McCarthy was famously reclusive and rarely gave interviews. He passed away on June 13, 2023.', 'Alive', '1933-07-20', 'author-101-cormac-mccarthy.jpg'),
(102, 'Fey', 'Tina', 'Elizabeth Stamatina Fey, known as Tina Fey, is an American comedian, writer, actress, and producer born on May 18, 1970, in Upper Darby, Pennsylvania. She graduated from the University of Virginia with a degree in drama and joined the improvisational comedy troupe The Second City in Chicago before joining Saturday Night Live in 1997. She became the show\'s first female head writer and created the recurring Weekend Update segment with Jimmy Fallon. Fey became internationally known for her uncanny impersonation of Sarah Palin during the 2008 election. She created and starred in the television series 30 Rock, which won numerous Emmy Awards. Her memoir Bossypants, published in 2011, became a number one bestseller and is celebrated for its sharp humor, candid reflections on body image, motherhood, and the difficulties of being a woman in comedy. Fey is widely regarded as one of the most influential comedic voices of her generation.', 'Alive', '1970-05-18', 'author-102-tina-fey.jpg'),
(103, 'Kinsella', 'Sophie', 'Sophie Kinsella is the pen name of Madeleine Wickham, a British author born on December 12, 1969, in London, England. She studied music at New College, Oxford, and worked as a financial journalist before turning to fiction. Kinsella created her most famous character, Becky Bloomwood, a hapless but lovable shopaholic financial journalist, in Confessions of a Shopaholic, published in 2000. The novel was a massive bestseller and launched the hugely popular Shopaholic series, which has sold over forty million copies worldwide. The first book was adapted into a film in 2009. Kinsella\'s novels are known for their warm humor, farcical situations, and deeply likable heroines. Under her real name, Wickham, she has also written a series of English country house novels. She is one of the bestselling chick lit authors in the world.', 'Alive', '1969-12-12', 'author-103-sophie-kinsella.jpg'),
(104, 'Hugo', 'Victor', 'Victor-Marie Hugo was a French poet, novelist, and dramatist born on February 26, 1802, in Besançon, France. He is considered the greatest French literary figure of the nineteenth century and one of the most important writers in the French language. Hugo was a child prodigy who began writing poetry at a young age and achieved success in multiple literary genres. His two most famous novels, The Hunchback of Notre-Dame, published in 1831, and Les Misérables, published in 1862, are among the most widely read novels ever written. Les Misérables, the sweeping epic of post-Napoleonic France following the ex-convict Jean Valjean\'s quest for redemption, has been adapted countless times for stage and screen, most famously as a long-running musical. Hugo was also a passionate political figure and an outspoken opponent of the death penalty and of Napoleon III. He spent nineteen years in political exile. He passed away on May 22, 1885, and was given a state funeral attended by two million people.', 'Dead', '1802-02-26', 'author-104-victor-hugo.jpg'),
(105, 'Fahnestock', 'Lee', 'Lee Fahnestock is an American translator known for her translations of French literature into English, including co-translating Victor Hugo\'s Les Misérables for the Modern Library edition. Her translation of Hugo\'s masterwork, undertaken with Norman MacAfee, is widely used in academic and popular editions and is praised for its clarity and faithfulness to Hugo\'s expansive, rhetorical style. Fahnestock\'s work has helped bring Hugo\'s powerful social vision to English-speaking readers across the world.', 'Alive', '1945-01-01', 'author-105-lee-fahnestock.jpg'),
(106, 'MacAfee', 'Norman', 'Norman MacAfee is an American translator and poet known for his translations of French and Italian literature. He co-translated Victor Hugo\'s Les Misérables with Lee Fahnestock, producing one of the widely used English editions of Hugo\'s monumental novel. MacAfee has also translated works by Italian poets and thinkers, contributing to the dissemination of European literature in English translation.', 'Dead', '1943-12-07', 'author-106-norman-macafee.jpg');
INSERT INTO `auteur` (`idAuteur`, `nom`, `prenom`, `description`, `status`, `dateNaiss`, `image`) VALUES
(107, 'Edwards', 'Kim', 'Kim Edwards is an American author who has lived and worked in Southeast Asia, Japan, and the United Kingdom, experiences that have deeply informed her fiction and poetry. She earned her MFA in creative writing and has taught at the University of Kentucky. Edwards is best known for her debut novel The Memory Keeper\'s Daughter, published in 2005, which tells the story of a doctor who secretly gives away his newborn daughter with Down syndrome on the night of her birth, a decision that haunts both families for decades. The novel became a massive bestseller, spending over two years on the New York Times bestseller list, and was adapted into a television film. Edwards\'s fiction is known for its emotional depth and its exploration of secrets, family, and the long consequences of a single moment.', 'Alive', '1958-01-01', 'author-107-kim-edwards.jpg'),
(108, 'Heller', 'Joseph', 'Joseph Heller was an American satirical author born on May 1, 1923, in Coney Island, Brooklyn, New York. He grew up in a poor Jewish family and served as a bombardier in the United States Army Air Forces during World War II, completing sixty combat missions. His experiences of the absurdity and horror of warfare became the foundation for his masterpiece, Catch-22, published in 1961. The novel, set at a fictional American air base in the Mediterranean during World War II, is a savage satirical comedy about military bureaucracy, institutional madness, and the impossible situation soldiers find themselves in. The phrase catch-22, meaning a no-win situation created by contradictory rules, has entered the English language as a common expression. Catch-22 is considered one of the greatest American novels of the twentieth century. Heller studied English at New York University and Columbia University and worked in advertising before achieving literary fame. He passed away on December 12, 1999.', 'Dead', '1923-05-01', 'author-108-joseph-heller.jpg'),
(109, 'Albom', 'Mitch', 'Mitch Albom is an American author, journalist, screenwriter, and playwright born on May 23, 1958, in Passaic, New Jersey. He studied sociology at Brandeis University and journalism at Columbia University. For many years, Albom was one of America\'s most prominent sports columnists, writing for the Detroit Free Press. He is best known for his inspirational non-fiction work Tuesdays with Morrie, published in 1997, which documents his Tuesday visits with his dying former sociology professor, Morrie Schwartz, and the life wisdom Morrie shared in his final months. The book became one of the longest-running bestsellers in American publishing history, selling over fourteen million copies worldwide. Albom went on to write several more bestselling books in a similar vein, including The Five People You Meet in Heaven and Have a Little Faith. He is also deeply involved in charitable work in Haiti.', 'Alive', '1958-05-23', 'author-109-mitch-albom.jpg'),
(110, 'Dagys', 'Saulius', 'Saulius Dagys is a Lithuanian translator known for his work translating significant works of world literature into Lithuanian. His translations have helped make important works of international fiction and nonfiction accessible to Lithuanian-speaking readers, contributing to the cultural life and literary development of Lithuania.', 'Alive', '1959-01-01', 'author-110-saulius-dagys.jpg'),
(111, 'Tan', 'Amy', 'Amy Tan is an American author born on February 19, 1952, in Oakland, California, to Chinese immigrant parents. She studied linguistics and earned a master\'s degree from San Jose State University. Tan worked as a business writer before turning to fiction. Her debut novel, The Joy Luck Club, published in 1989, tells the stories of four Chinese-American immigrant families through alternating narratives of mothers and daughters, exploring the cultural tensions and deep bonds between generations. The novel became an immediate bestseller and was a finalist for the National Book Award and the National Book Critics Circle Award. It was adapted into a film in 1993. Tan is known for her emotionally rich portrayal of the Chinese-American immigrant experience, the complexity of mother-daughter relationships, and the way cultural heritage and identity are transmitted and transformed across generations. She has also written a memoir, The Opposite of Fate.', 'Alive', '1952-02-19', 'author-111-amy-tan.jpg'),
(112, 'Atwood', 'Margaret', 'Margaret Eleanor Atwood is a Canadian author, poet, literary critic, and environmental activist born on November 18, 1939, in Ottawa, Ontario. She is one of the most celebrated and decorated writers in the world, having published over seventeen novels as well as poetry, short fiction, literary criticism, and graphic novels. Atwood studied English at Victoria College, University of Toronto, and later at Radcliffe College at Harvard. She is best known for her dystopian novel The Handmaid\'s Tale, published in 1985, which imagines a totalitarian theocracy in which women\'s bodies are controlled by the state. The novel, which draws on historical practices for all of its events, became a classic of feminist literature and gained renewed relevance with the political climate of the 2010s, inspiring a critically acclaimed television adaptation. Atwood has received numerous awards, including two Man Booker Prizes, the Pen Pinter Prize, and the Franz Kafka Prize. She is a passionate environmentalist and advocate for human rights.', 'Alive', '1939-11-18', 'author-112-margaret-atwood.jpg'),
(113, 'Brashares', 'Ann', 'Ann Brashares is an American author born on July 30, 1967, in Chevy Chase, Maryland. She studied philosophy at Barnard College in New York City. Before becoming an author, Brashares worked as an editorial assistant and editor at a publishing company in New York. She is best known for The Sisterhood of the Traveling Pants, published in 2001, the first in a four-book series about four best friends who spend a summer apart but stay connected through a magical pair of jeans that fits all of them perfectly despite their different body types. The series became a beloved staple of young adult fiction and was adapted into two popular films. Brashares\'s work is celebrated for its warm portrayal of female friendship, its emotional honesty, and its ability to capture the experiences of teenage girls with authenticity and depth.', 'Alive', '1967-07-30', 'author-113-ann-brashares.jpg'),
(114, 'Nabokov', 'Vladimir', 'Vladimir Vladimirovich Nabokov was a Russian-American novelist, poet, critic, translator, and lepidopterist born on April 22, 1899, in Saint Petersburg, Russia. He came from an aristocratic family and was raised speaking Russian, English, and French. Following the Russian Revolution, the family fled Russia, and Nabokov spent years in Cambridge, Berlin, and Paris before emigrating to the United States in 1940. In Europe, Nabokov wrote nine novels in Russian, establishing himself as a major literary figure. In America, he switched to English and gained international fame with Lolita, published in 1955, a controversial and stylistically brilliant novel narrated by a pedophile. Despite its disturbing subject matter, the novel is celebrated as one of the great works of twentieth-century literature for its extraordinary prose style. His other celebrated English novels include Pale Fire and Ada, or Ardor. Nabokov was also a distinguished researcher and curator of Lepidoptera at Harvard\'s Museum of Comparative Zoology. He passed away on July 2, 1977.', 'Dead', '1899-04-22', 'author-114-vladimir-nabokov.jpg'),
(115, 'Raine', 'Craig', 'Craig Raine is a British poet, critic, and author born on December 3, 1944, in Shildon, County Durham, England. He studied at Exeter College, Oxford, and later became a Fellow of New College, Oxford. Raine is best known as the founder of the Martian School of Poetry, a movement that sought to defamiliarize everyday objects and experiences by describing them as an alien or Martian visitor might see them, making the familiar strange and fresh. His most celebrated poetry collection, A Martian Sends a Postcard Home, published in 1979, gives the movement its name. Raine has also worked as a poetry editor and literary critic, edited the literary magazine Areté, and written prose fiction, plays, and criticism. He is widely regarded as one of the most inventive and influential British poets of his generation.', 'Alive', '1944-12-03', 'author-115-craig-raine.jpg'),
(116, 'Maguire', 'Gregory', 'Gregory Maguire is an American author born on June 9, 1954, in Albany, New York. He studied English and children\'s literature and earned a doctorate from Tufts University. Maguire is best known for his revisionist fairy tales and fantasies for adults that retell classic stories from the perspective of the villain or the overlooked character. His most celebrated novel, Wicked: The Life and Times of the Wicked Witch of the West, published in 1995, retells L. Frank Baum\'s The Wonderful Wizard of Oz from the perspective of Elphaba, the misunderstood witch. The novel became a massive bestseller and was adapted into the hugely successful Broadway musical Wicked, which ran for over twenty years and became one of the most financially successful musicals in theater history. Maguire has written other revisionist works drawing on Cinderella, Snow White, and A Christmas Carol, among others.', 'Alive', '1954-06-09', 'author-116-gregory-maguire.jpg'),
(117, 'Smith', 'Douglas', 'Douglas Smith is a translator and author known for his translations of major works of Russian history and literature into English. He has translated works related to Russian imperial history and Enlightenment Russia, contributing to academic and popular understanding of Russian culture and history. His translations are praised for their accuracy and their ability to make complex Russian texts accessible to English-speaking audiences.', 'Alive', '1942-01-01', 'author-117-douglas-smith.jpg'),
(118, 'Andrews', 'Richard', 'Richard Andrews is a British academic and author known for his work in the field of education, rhetoric, and research methodology. He has written extensively on argument, essay writing, and the teaching of English, and has contributed to understanding of how students learn to write and reason. Andrews has been a professor at various universities and is considered an important figure in the field of educational research and literacy studies.', 'Alive', '1940-01-01', 'author-118-richard-andrews.jpg'),
(119, 'Gibson', 'Rex', 'Rex Gibson was a British educator and author who dedicated much of his career to making Shakespeare accessible and engaging for students and teachers. He directed the Cambridge Shakespeare and Schools Project and edited the Cambridge School Shakespeare series, producing classroom editions of Shakespeare\'s plays that have been widely used in schools across the United Kingdom and beyond. Gibson\'s editions are known for their practical, activity-based approach to teaching Shakespeare, emphasizing performance and active engagement with the texts over passive reading. His work transformed the way Shakespeare is taught in secondary schools.', 'Alive', '1932-01-01', 'author-119-rex-gibson.jpg'),
(120, 'Gladwell', 'Malcolm', 'Malcolm Gladwell is a Canadian journalist and author born on September 3, 1963, in Fareham, Hampshire, England, who grew up in rural Ontario, Canada. He studied history at the University of Toronto and has been a staff writer at The New Yorker since 1996. Gladwell is known for his ability to synthesize research from psychology, sociology, and economics into highly readable narratives that challenge conventional wisdom about human behavior and success. His debut book, The Tipping Point, published in 2000, examined how small events can trigger social epidemics. His subsequent books, including Blink, Outliers, and David and Goliath, all became major international bestsellers. Gladwell is particularly known for popularizing the idea that it takes roughly ten thousand hours of deliberate practice to achieve mastery in any field, and for exploring how cultural background, timing, and hidden advantages shape success. He is one of the most influential non-fiction writers of the early twenty-first century.', 'Alive', '1963-09-03', 'author-120-malcolm-gladwell.jpg'),
(121, 'Isaacson', 'Walter', 'Walter Isaacson is an American author, journalist, and educator born on May 20, 1952, in New Orleans, Louisiana. He studied history and literature at Harvard University and later went to Oxford as a Rhodes Scholar. Isaacson has had distinguished careers in both journalism and academia, serving as the chairman and CEO of CNN and as the editor of Time magazine before becoming president of the Aspen Institute. He is best known as a biographer of major historical and contemporary figures, including Benjamin Franklin, Albert Einstein, Steve Jobs, Leonardo da Vinci, and Elon Musk. His authorized biography of Steve Jobs, published in 2011, is one of the bestselling biographies of all time, based on over forty interviews with Jobs and was released just weeks after Jobs\'s death. Isaacson\'s biographies are known for their meticulous research, balanced assessment, and accessible narrative style.', 'Alive', '1952-05-20', 'author-121-walter-isaacson.jpg'),
(122, 'Kesey', 'Ken', 'Ken Elton Kesey was an American novelist and countercultural figure born on September 17, 1935, in La Junta, Colorado. He grew up in Oregon and studied creative writing at Stanford University under Wallace Stegner. While at Stanford, Kesey participated in government experiments with psychedelic drugs at the Veterans Administration Hospital in Menlo Park, experiences that profoundly influenced his writing and worldview. His first novel, One Flew Over the Cuckoo\'s Nest, published in 1962, is narrated by Chief Bromden, a patient in a psychiatric hospital, and chronicles the battle between the rebellious Randle McMurphy and the authoritarian Nurse Ratched. The novel became one of the defining works of the 1960s counterculture and was adapted into a celebrated 1975 film starring Jack Nicholson that won five Academy Awards. Kesey was also the leader of the Merry Pranksters, a group who traveled across America in a bus promoting the psychedelic experience. He passed away on November 10, 2001.', 'Dead', '1935-09-17', 'author-122-ken-kesey.jpg'),
(123, 'Hemingway', 'Ernest', 'Ernest Miller Hemingway was an American author and journalist born on July 21, 1899, in Oak Park, Illinois. He is one of the most influential writers of the twentieth century, known for his economical, iceberg-style prose in which much of the meaning lies beneath the surface of the text. Hemingway worked as an ambulance driver in World War I, a war correspondent in the Spanish Civil War, and World War II, and his first-hand experience of war, hunting, fishing, and bullfighting permeates his work. His novels include The Sun Also Rises, A Farewell to Arms, For Whom the Bell Tolls, and The Old Man and the Sea, the last of which won the Pulitzer Prize and contributed significantly to his being awarded the Nobel Prize in Literature in 1954. Hemingway spent much of his adult life in Paris, Key West, Cuba, and Idaho. He struggled with depression and physical decline in his later years and died by suicide on July 2, 1961.', 'Dead', '1899-07-21', 'author-123-ernest-hemingway.jpg'),
(124, 'Montgomery', 'L.M.', 'Lucy Maud Montgomery was a Canadian author born on November 30, 1874, in Clifton, Prince Edward Island. She is best known for creating the character of Anne Shirley, the spirited, red-haired orphan at the center of the Anne of Green Gables series. The first book, Anne of Green Gables, published in 1908, became an immediate bestseller in Canada and internationally and cemented Prince Edward Island as a major literary destination. Montgomery drew heavily on her own childhood on Prince Edward Island, her love of nature, and her experiences as an orphan raised by strict grandparents. The Anne series grew to eight books, and the character has become a beloved and enduring figure in world literature. Montgomery was also a prolific writer of short stories and poems. She struggled with depression throughout her life and passed away on April 24, 1942.', 'Dead', '1874-11-30', 'author-124-lm-montgomery.jpg'),
(125, 'Wells', 'Rebecca', 'Rebecca Wells is an American author and playwright born on October 16, 1952, in Louisiana. She grew up in central Louisiana, and her Southern heritage deeply informs her fiction. Wells studied theater at Louisiana State University and later at the University of Washington. She worked as an actress, playwright, and performance artist before turning to fiction. Her debut novel Little Altars Everywhere introduced the Ya-Ya Sisterhood characters, but it was the sequel Divine Secrets of the Ya-Ya Sisterhood, published in 1996, that became a publishing phenomenon, spending over two years on the New York Times bestseller list after years of building word-of-mouth success. The novel explores the complex and painful relationship between a mother and daughter and the bonds of female friendship. It was adapted into a film starring Sandra Bullock and Ellen Burstyn in 2002.', 'Alive', '1952-01-01', 'author-125-rebecca-wells.jpg'),
(126, 'Gabaldon', 'Diana', 'Diana Gabaldon is an American author born on January 11, 1952, in Flagstaff, Arizona. She earned a bachelor\'s degree in zoology, a master\'s degree in marine biology, and a Ph.D. in behavioral ecology from Northern Arizona University, and worked as a university professor and researcher before becoming a novelist. Gabaldon began writing what would become Outlander in 1988 as a practice exercise, intending it never to be published. The novel, which blends historical fiction, romance, time travel, and adventure by following a World War II nurse who travels back in time to eighteenth-century Scotland, was published in 1991. The Outlander series grew to nine main novels and multiple companion books, selling tens of millions of copies worldwide. A successful television adaptation premiered on Starz in 2014 and ran for seven seasons. Gabaldon is celebrated for her extraordinary depth of historical research and her compulsively readable narrative style.', 'Alive', '1952-01-11', 'author-126-diana-gabaldon.jpg'),
(127, 'Hawthorne', 'Nathaniel', 'Nathaniel Hawthorne was an American novelist and short-story writer born on July 4, 1804, in Salem, Massachusetts. He is one of the central figures of American literature and was deeply preoccupied with the moral legacy of Puritanism, sin, and guilt that he saw as central to the American character. Hawthorne was descended from John Hathorne, one of the judges in the Salem witch trials, and his family\'s participation in that dark chapter of American history haunted his imagination and shaped his writing. He is best known for The Scarlet Letter, published in 1850, a masterwork of American fiction set in seventeenth-century Puritan Boston that explores adultery, guilt, sin, and redemption through the story of Hester Prynne. He also wrote The House of the Seven Gables and Twice-Told Tales. Hawthorne was a close friend of Herman Melville, to whom Moby-Dick was dedicated. He passed away on May 19, 1864.', 'Dead', '1804-07-04', 'author-127-nathaniel-hawthorne.jpg'),
(128, 'E. Connolly', 'Thomas', 'Thomas E. Connolly was an American academic and literary scholar known for his work on James Joyce and other modernist authors. He edited and contributed to scholarly volumes on Joyce\'s manuscripts and literary legacy, including work on Joyce\'s notebooks and drafts. His contributions to Joyce scholarship helped illuminate the complex process by which Joyce composed his major works.', 'Alive', '1918-01-01', 'author-128-thomas-e-connolly.jpg'),
(129, 'Baym', 'Nina', 'Nina Baym is an American literary scholar born in 1936, known as one of the most influential figures in the study of American literature and women\'s writing. She is a professor emerita at the University of Illinois at Urbana-Champaign. Baym served as the general editor of The Norton Anthology of American Literature for many years and is known for her groundbreaking scholarship on nineteenth-century American women\'s fiction, particularly her book Woman\'s Fiction, which challenged the traditional male-dominated literary canon by examining a large body of fiction by women writers that had been largely ignored by academic criticism.', 'Alive', '1936-01-01', 'author-129-nina-baym.jpg'),
(130, 'Riggs', 'Ransom', 'Ransom Riggs is an American author born on October 3, 1979, in Williamsburg, Virginia, who grew up in Englewood, Florida. He studied English literature at Kenyon College and filmmaking at the University of Southern California. Riggs developed a unique creative approach of building stories around collections of found vintage photographs, using the eerie and mysterious images to inspire his narratives. His debut novel Miss Peregrine\'s Home for Peculiar Children, published in 2011, became an international bestseller, blending fantasy, mystery, and horror around a home for children with supernatural abilities. The novel and its sequels were adapted into a film directed by Tim Burton in 2016. Riggs is also a filmmaker, traveler, and collector of vintage photographs, and his work is distinguished by its visual originality and its ability to evoke a genuinely uncanny atmosphere.', 'Alive', '1979-10-19', 'author-130-ransom-riggs.jpg'),
(131, 'Weir', 'Andy', 'Andy Weir is an American author born on June 16, 1972, in Davis, California. He is the son of a particle physicist and a electrical engineer, and has been deeply interested in science from childhood. Weir worked as a software engineer for major technology companies, including Blizzard Entertainment, while pursuing writing as a hobby. He self-published The Martian as a serial on his personal website in 2011, then made it available as an e-book at the minimum price, from which it was picked up by a publisher in 2013. The Martian tells the story of an astronaut stranded alone on Mars who must use his scientific knowledge to survive. The novel became a massive bestseller and was adapted into a critically acclaimed film directed by Ridley Scott and starring Matt Damon in 2015, earning seven Academy Award nominations. Weir is celebrated for making rigorous science entertaining and accessible.', 'Alive', '1972-06-16', 'author-131-andy-weir.jpg'),
(132, 'Follett', 'Ken', 'Ken Follett is a Welsh author born on June 5, 1949, in Cardiff, Wales. He studied philosophy at University College London and worked as a journalist and publisher before becoming a novelist. Follett first achieved widespread recognition with his thriller Eye of the Needle, published in 1978, but his greatest achievement is the historical novel The Pillars of the Earth, published in 1989. Set in twelfth-century England and centered on the building of a cathedral in the fictional town of Kingsbridge, the novel is an extraordinary blend of architectural history, medieval politics, and human drama. Despite mixed initial critical reception, the novel became one of the most beloved popular historical novels of all time, selling over twenty-six million copies. It was followed by a sequel, World Without End, and a prequel, The Evening and the Morning. Follett is also known for his Century trilogy, tracing three families through the twentieth century.', 'Alive', '1949-06-05', 'author-132-ken-follett.jpg'),
(133, 'Doerr', 'Anthony', 'Anthony Doerr is an American author born in 1973 in Cleveland, Ohio. He studied history at Bowdoin College and creative writing at Bowling Green State University. Doerr has published several short story collections and novels, and is known for his lyrical prose and his keen attention to science, nature, and the physical world. His second novel, All the Light We Cannot See, published in 2014, is set during World War II and follows two young people, a blind French girl and a German boy, whose lives converge in occupied France. The novel spent more than two years on the New York Times bestseller list, won the Pulitzer Prize for Fiction in 2015, and the Andrew Carnegie Medal for Excellence in Fiction. It was adapted into a Netflix television series in 2023. Doerr is widely regarded as one of the finest prose stylists working in American fiction today.', 'Alive', '1973-10-27', 'author-133-anthony-doerr.jpg'),
(134, 'Hillenbrand', 'Laura', 'Laura Hillenbrand is an American author born on May 15, 1967, in Fairfax, Virginia. She studied history at Kenyon College but was forced to leave due to a severe case of chronic fatigue syndrome, a debilitating illness that has largely confined her to her home for decades. Despite this extraordinary challenge, Hillenbrand has written two of the most acclaimed and successful nonfiction narratives of recent times. Seabiscuit: An American Legend, published in 2001, tells the story of the Depression-era racehorse who became a symbol of hope for a struggling nation, and became a major bestseller and film. Her second book, Unbroken, published in 2010, is the remarkable true story of Louis Zamperini, an Olympic runner who survived a plane crash, forty-seven days adrift on a raft, and years as a Japanese prisoner of war. Unbroken spent over four years on the bestseller list and was adapted into a film by Angelina Jolie.', 'Alive', '1967-05-15', 'author-134-laura-hillenbrand.jpg'),
(135, 'Tartt', 'Donna', 'Donna Tartt is an American author born on December 23, 1963, in Greenwood, Mississippi. She studied classics at Bennington College in Vermont, where she began writing what would become her debut novel. Tartt is known for writing very slowly and very carefully, publishing only three novels over the course of more than thirty years, each of which has been a major event in literary fiction. Her debut, The Secret History, published in 1992, is a dark, intellectually rich thriller set at a small Vermont college about a group of classics students who commit murder. Her second novel, The Little Friend, was published in 2002. Her third novel, The Goldfinch, published in 2013, tells the story of a boy whose life is shaped by the theft of a famous Dutch painting following a terrorist attack. The Goldfinch was a massive international bestseller and won the Pulitzer Prize for Fiction in 2014.', 'Alive', '1963-12-23', 'author-135-donna-tartt.jpg'),
(136, 'Chevalier', 'Tracy', 'Tracy Chevalier is an American-British author born on October 19, 1962, in Washington, D.C. She grew up in Washington but moved to England in her twenties and has lived there since. Chevalier studied English at Oberlin College and creative writing at the University of East Anglia. She is best known for her historical novel Girl with a Pearl Earring, published in 1999, which imagines the story behind Vermeer\'s famous painting of the same name. The novel became an international bestseller and was adapted into a film starring Scarlett Johansson and Colin Firth in 2003. Chevalier is known for writing historical fiction centered on works of art, crafting novels that bring to life the people and worlds behind iconic paintings and tapestries. Her other works include The Virgin Blue, Falling Angels, and A Single Thread.', 'Alive', '1962-10-19', 'author-136-tracy-chevalier.jpg'),
(137, 'Forman', 'Gayle', 'Gayle Forman is an American author and journalist born on June 5, 1970, in Los Angeles, California. She studied journalism at the University of Oregon and spent many years as a journalist, writing for publications including Seventeen magazine. Her debut young adult novel Sisters in Sanity was published in 2007, but it was her second novel, If I Stay, published in 2009, that brought her international recognition. The novel tells the story of a teenage musician who, lying in a coma after a car accident, must decide whether to live or die. The novel became a massive bestseller and was adapted into a film in 2014. Forman is known for her emotionally intense narratives, her authentic portrayals of teenage life, and her ability to tackle profound themes of grief, love, and identity with sensitivity and depth.', 'Alive', '1970-06-05', 'author-137-gayle-forman.jpg'),
(138, 'Diamant', 'Anita', 'Anita Diamant is an American author and journalist born on June 27, 1951, in Newark, New Jersey. She studied English at Washington University in St. Louis and the University of Denver. Diamant has written several nonfiction books on contemporary Jewish life and practice, as well as journalism for newspapers and magazines. She is best known for her debut novel The Red Tent, published in 1997, which retells the story of Dinah, a minor biblical character from the Book of Genesis, imagining her life and that of the women of her time in vivid, feminist detail. The novel, which takes its title from the tent where women gathered during their menstrual periods in ancient times, was passed from reader to reader by word of mouth for years before becoming a major bestseller. It was adapted into a television miniseries in 2014. Diamant is also the founder of Mayyim Hayyim, a Jewish community mikveh in Newton, Massachusetts.', 'Alive', '1951-06-27', 'author-138-anita-diamant.jpg'),
(139, 'Sparks', 'Nicholas', 'Nicholas Sparks is an American romance author born on December 31, 1965, in Omaha, Nebraska. He studied business at the University of Notre Dame and worked various jobs, including as a waiter, real estate salesman, and pharmaceutical sales representative, before achieving literary success. His debut novel The Notebook, published in 1996, the story of a young couple from different social backgrounds whose love endures the tests of war, separation, and eventually Alzheimer\'s disease, became a phenomenon after being adapted into a hugely popular film in 2004. Sparks has since become one of the most commercially successful romance authors in the world, publishing over twenty novels, nearly all of which have been adapted into films. His novels are set predominantly in small-town North Carolina and are known for their heartfelt emotional narratives, which frequently involve themes of love, tragedy, and loss.', 'Alive', '1965-12-31', 'author-139-nicholas-sparks.jpg'),
(140, 'Giffin', 'Emily', 'Emily Giffin is an American author born on March 20, 1972, in Baltimore, Maryland. She grew up in Naperville, Illinois, studied English at Wake Forest University, and then earned her law degree from the University of Virginia School of Law. Giffin practiced law in New York and London before leaving to write fiction. Her debut novel Something Borrowed, published in 2004, tells the story of a woman who falls in love with her best friend\'s fiancé and became a major bestseller, eventually adapted into a film in 2011. Giffin is known for her commercial women\'s fiction that tackles real moral complexity in relationships, exploring themes of friendship, love, infidelity, and the difficult choices people make in pursuit of happiness. She has published numerous other bestselling novels, and is celebrated for creating characters who feel genuinely real and flawed.', 'Alive', '1972-03-19', 'author-140-emily-giffin.jpg'),
(141, 'Seuss', 'Dr.', 'Theodor Seuss Geisel, known to the world as Dr. Seuss, was an American children\'s book author and illustrator born on March 2, 1904, in Springfield, Massachusetts. He studied English at Dartmouth College and briefly attended Lincoln College, Oxford, where he intended to pursue a doctorate but never completed it. He adopted the pen name Seuss as a self-mocking reference to his unfinished academic career. Geisel worked as an illustrator and political cartoonist before publishing his first children\'s book And to Think That I Saw It on Mulberry Street in 1937, after being rejected by dozens of publishers. His early reader The Cat in the Hat, published in 1957, was created in response to criticism that early reading books were boring, and was a breakthrough in children\'s literature, deliberately limited to a vocabulary list while remaining playful and entertaining. Geisel published over sixty books in his lifetime, selling over 650 million copies worldwide, and is one of the bestselling children\'s authors of all time. He passed away on September 24, 1991.', 'Dead', '1904-03-02', 'author-141-dr-seuss.jpg'),
(143, 'Dahl', 'Roald', 'Roald Dahl was a British novelist, short story writer, screenwriter, and wartime fighter pilot born on September 13, 1916, in Llandaff, Cardiff, Wales, to Norwegian parents. He is one of the world\'s bestselling authors and is particularly beloved for his darkly comic, inventive, and sometimes macabre children\'s books, as well as his sinister adult short fiction. Dahl served in the Royal Air Force during World War II and was badly injured in a crash in the Libyan desert. His children\'s novels include James and the Giant Peach, Charlie and the Chocolate Factory, Matilda, The BFG, Fantastic Mr Fox, and The Witches, all of which have been adapted for film and stage multiple times. Dahl\'s stories are characterized by their wicked humor, imaginative excess, and a sympathetic portrayal of the perspective of children navigating an often hostile adult world. He passed away on November 23, 1990.', 'Alive', '1916-09-13', 'author-143-roald-dahl.jpg'),
(144, 'Blake', 'Quentin', 'Quentin Blake is a British illustrator, author, and art director born on December 16, 1932, in Sidcup, Kent, England. He studied English at Downing College, Cambridge, and later at the Chelsea School of Art. Blake is one of the most celebrated illustrators in the world, best known for his long and fruitful collaboration with Roald Dahl, whose children\'s books he illustrated over many decades, creating an instantly recognizable visual style that has become inseparable from Dahl\'s words. His loose, energetic, expressive line drawings have illustrated over three hundred books. Blake was appointed the first Children\'s Laureate of the United Kingdom in 1999, a role he used to promote illustration as a serious art form and to increase access to books for children. He is also known for his large-scale illustrated murals in hospitals, including the Evelina London Children\'s Hospital, and for his work at the House of Illustration in London.', 'Alive', '1932-12-16', 'author-144-quentin-blake.jpg'),
(145, 'Camus', 'Albert', 'Albert Camus was a French-Algerian philosopher, author, and journalist born on November 7, 1913, in Mondovi, Algeria. He is one of the most important literary and philosophical figures of the twentieth century, closely associated with existentialism and absurdism, though he himself rejected the existentialist label. Camus grew up in poverty in Algiers and studied philosophy at the University of Algiers before moving to mainland France. He worked as a journalist and was active in the French Resistance during World War II, editing the underground newspaper Combat. His debut novel The Stranger, published in 1942, and its companion philosophical essay The Myth of Sisyphus established the concept of the absurd as a central feature of modern thought. His other major works include The Plague and The Fall. Camus was awarded the Nobel Prize in Literature in 1957, becoming the second-youngest recipient at the time. He died in a car accident on January 4, 1960.', 'Dead', '1913-11-07', 'author-145-albert-camus.jpg'),
(146, 'Ward', 'Matthew', 'Matthew Ward is an American translator known for his work translating French literature into English. He is particularly recognized for his translation of Albert Camus\'s The Stranger, published by Vintage Books in 1989. Ward\'s translation replaced an earlier rendering by Stuart Gilbert and is widely considered more accurate and stylistically faithful to the terse, flat, alienated voice of Camus\'s original French. His translation is now the standard edition used in universities and classrooms across the English-speaking world.', 'Alive', '1951-01-01', 'author-146-matthew-ward.jpg'),
(147, 'Rowell', 'Rainbow', 'Rainbow Rowell is an American author born on February 24, 1973, in Omaha, Nebraska. She studied English and journalism at the University of Nebraska and worked as a journalist and advertising copywriter before turning to fiction. Rowell is known for her deeply character-driven novels that blend romance with sharply observed portrayals of contemporary life, fandom, and the transformative power of love. Her novels include Eleanor and Park, Fangirl, Attachments, and Landline, all of which received widespread critical acclaim and passionate readerships. Eleanor and Park, published in 2013, tells the story of two misfits who fall in love on a school bus in 1986 Omaha and is considered one of the finest young adult novels of the decade. Rowell has also written the Carry On fantasy series and has contributed to Marvel comic book writing. Her work is beloved for its authenticity, humor, and emotional generosity.', 'Alive', '1973-02-24', 'author-147-rainbow-rowell.jpg'),
(148, 'Condie', 'Ally', 'Ally Condie is an American young adult author born on November 5, 1978, in Utah. She studied English at Brigham Young University and worked as a high school English teacher before becoming a full-time novelist. Condie is best known for the Matched trilogy, a dystopian young adult series set in a future society called the Society, which dictates every aspect of its citizens\' lives, including whom they will marry. The first book, Matched, published in 2010, became a New York Times bestseller and launched a successful franchise. The series is notable for its lyrical prose style and its thematic focus on the importance of individual choice and the power of art and poetry in resisting oppression. Condie is also known for her love of literature, her use of poetry as a narrative device, and her involvement in the writing community.', 'Alive', '1978-02-05', 'author-148-ally-condie.jpg'),
(149, 'Gaiman', 'Neil', 'Neil Richard Gaiman is a British author born on November 10, 1960, in Portchester, Hampshire, England. He is one of the most versatile and celebrated storytellers working today, having written acclaimed work in virtually every narrative medium including novels, short fiction, comic books, screenplays, and children\'s books. Gaiman began his career as a journalist before breaking into comics with the groundbreaking Sandman series for DC/Vertigo, which transformed the medium with its literary sophistication and mythological scope. His novels include American Gods, which won the Hugo, Nebula, and Bram Stoker awards; Neverwhere; Stardust; and the terrifying children\'s novel Coraline. His children\'s picture book The Wolves in the Walls and the novella The Ocean at the End of the Lane are also widely beloved. Gaiman\'s writing draws on an extraordinary breadth of mythology, folklore, and literary tradition, combined with a distinctly modern sensibility and a gift for horror and wonder.', 'Alive', '1960-11-10', 'author-149-neil-gaiman.jpg'),
(150, 'Wrightson', 'Bernie', 'Bernie Wrightson was an American comic book artist and illustrator born on October 27, 1948, in Collingdale, Pennsylvania. He is widely regarded as one of the greatest horror illustrators in the history of comic books. Wrightson began his career in the late 1960s and rose to fame as the co-creator of the DC Comics character Swamp Thing alongside Len Wein in 1971, producing some of the most haunting and expressively detailed horror artwork ever seen in comics. He later produced a celebrated illustrated edition of Mary Shelley\'s Frankenstein, spending seven years creating over fifty detailed pen and ink illustrations that have become classic works of horror art. Wrightson worked with Stephen King on illustrated editions of The Stand and Cycle of the Werewolf. He was a founding member of the studio known as the Crusty Bunkers, a group of influential comics artists of the 1970s. Wrightson passed away on March 18, 2017.', 'Dead', '1948-10-27', 'author-150-bernie-wrightson.jpg'),
(151, 'Stafford', 'Fiona', 'Fiona Stafford is a British literary scholar and academic known for her work on Romantic literature, Scottish literature, and the cultural significance of trees and nature in literary tradition. She is a professor of English at Somerville College, University of Oxford. Her books include The Last of the Race, a study of the cult of the last man in Romantic literature, and Local Attachments: The Province of Poetry, as well as popular works on the cultural and historical significance of particular species of trees. Stafford writes accessibly and engagingly about literature and nature for both academic and general audiences.', 'Alive', '1958-01-01', 'author-151-fiona-stafford.jpg'),
(152, 'Tolstoy', 'Leo', 'Count Lev Nikolayevich Tolstoy was a Russian novelist, short story writer, essayist, and moral philosopher born on September 9, 1828, on his family\'s estate Yasnaya Polyana, in Tula, Russia. He is widely regarded as one of the greatest authors in the history of world literature. Tolstoy studied law and Oriental languages at Kazan University but left without a degree. He served in the army during the Crimean War, experiences that deeply affected his moral views. His two masterworks, War and Peace, published between 1865 and 1869, and Anna Karenina, published between 1875 and 1877, are considered among the greatest novels ever written. War and Peace is an epic narrative of Russian society during the Napoleonic Wars, while Anna Karenina is a searching examination of love, morality, and society. In his later years, Tolstoy underwent a profound spiritual crisis and became a moral and religious reformer, renouncing his aristocratic privileges. He passed away on November 20, 1910.', 'Dead', '1828-09-09', 'author-152-leo-tolstoy.jpg'),
(153, 'Maude', 'Louise', 'Louise Maude was a British translator who worked in close collaboration with her husband Aylmer Maude to produce some of the most widely used English translations of Leo Tolstoy\'s works. The Maudes were close personal friends of Tolstoy and spent time at Yasnaya Polyana, and their translations were authorized and personally approved by Tolstoy himself. Their translations of War and Peace, Anna Karenina, and other Tolstoy works are celebrated for their fidelity and readability, and remain standard translations used in academic and popular editions around the world.', 'Dead', '1855-01-01', 'author-153-louise-maude.jpg'),
(154, 'Tolstoj', 'Leo', 'Count Lev Nikolayevich Tolstoy, also rendered as Tolstoj in various European traditions, was a Russian novelist, short story writer, essayist, and moral philosopher born on September 9, 1828, on his family\'s estate Yasnaya Polyana, in Tula, Russia. He is widely regarded as one of the greatest authors in the history of world literature. His two masterworks, War and Peace and Anna Karenina, are considered among the greatest novels ever written. Anna Karenina, published serially between 1875 and 1877, explores the fatal love affair of the married aristocrat Anna Karenina and the dashing officer Count Vronsky against the backdrop of Russian high society, alongside the contrasting story of the farmer and philosopher Levin\'s search for meaning and happiness. Tolstoy himself considered it his first true novel, and it has been consistently ranked among the greatest works of fiction in literary history. In his later years, Tolstoy became a major moral and religious reformer. He died on November 20, 1910.', 'Dead', '1828-09-09', 'author-154-leo-tolstoj.jpg'),
(155, 'Dostoyevsky', 'Fyodor', 'Fyodor Mikhailovich Dostoyevsky was a Russian novelist, short story writer, essayist, and journalist born on November 11, 1821, in Moscow, Russia. He is one of the supreme masters of world literature and a profound explorer of the human psyche, morality, and the nature of suffering. Dostoyevsky studied military engineering and served briefly as an officer before devoting himself to literature. His early literary success was followed by arrest for alleged political conspiracy, and he spent four years in a Siberian labor camp, an experience that transformed his religious outlook and profoundly deepened his writing. His major novels include Crime and Punishment, The Idiot, Demons, and The Brothers Karamazov, considered by many critics to be the greatest novel ever written. His works delve into themes of free will, faith, nihilism, suffering, and redemption with extraordinary psychological insight. Dostoyevsky passed away on February 9, 1881.', 'Dead', '1821-11-11', 'author-155-fyodor-dostoyevsky.jpg'),
(156, 'McDuff', 'David', 'David McDuff is a British translator known for his translations of Russian and Scandinavian literature for Penguin Classics. He has produced widely used translations of major works by Fyodor Dostoyevsky, including The Brothers Karamazov, Crime and Punishment, The Idiot, and Notes from Underground, as well as translations of other Russian and Finnish authors. McDuff\'s translations are praised for their accessibility and their ability to render the psychological depth and tonal range of these great nineteenth-century works in contemporary, readable English.', 'Alive', '1945-01-01', 'author-156-david-mcduff.jpg'),
(157, 'Plath', 'Sylvia', 'Sylvia Plath was an American poet, novelist, and short story writer born on October 27, 1932, in Boston, Massachusetts. She is one of the most celebrated and influential poets of the twentieth century, known for her confessional poetry that explored themes of death, rebirth, female identity, and psychological anguish with extraordinary intensity and craftsmanship. Plath studied at Smith College and won a Fulbright Scholarship to Newnham College, Cambridge, where she met and married the poet Ted Hughes. She suffered from severe depression throughout her life and documented her experiences in The Bell Jar, published under the pseudonym Victoria Lucas in 1963, a semi-autobiographical novel about a young woman\'s mental breakdown. Plath\'s poetry collections include The Colossus and the posthumously published Ariel, which established her legendary reputation. She died by suicide on February 11, 1963, at the age of thirty. Her Collected Poems won the Pulitzer Prize in 1982, making her the only poet to win the award posthumously.', 'Dead', '1932-10-27', 'author-157-sylvia-plath.jpg'),
(158, 'McCourt', 'Frank', 'Francis McCourt was an Irish-American author and teacher born on August 19, 1930, in Brooklyn, New York, to recent Irish immigrants. His family returned to Ireland when he was four years old, and he grew up in extreme poverty in Limerick during the Great Depression and World War II. McCourt spent decades as a writing teacher in New York City public schools and at Stuyvesant High School. He began writing his memoir in his sixties and published Angela\'s Ashes in 1996, at the age of sixty-six. The memoir, which recounts his impoverished childhood in Limerick with dark humor and extraordinary vividness, won the Pulitzer Prize for Biography or Autobiography, the National Book Critics Circle Award, and the Los Angeles Times Book Award, and became one of the bestselling memoirs in American history. It was adapted into a film in 1999. McCourt followed it with two more memoirs, Tis and Teacher Man. He passed away on July 19, 2009.', 'Dead', '1930-08-19', 'author-158-frank-mccourt.jpg'),
(159, 'Hesse', 'Hermann', 'Hermann Hesse was a German-Swiss poet, novelist, and painter born on July 2, 1877, in Calw, in the Kingdom of Württemberg. He is one of the most widely read German-language authors of the twentieth century, known for his introspective novels exploring the individual\'s search for identity, spirituality, and self-knowledge. Hesse grew up in a deeply religious household with missionary connections to India, and Eastern philosophy, Jungian psychology, and the German Romantic tradition all profoundly shaped his work. His major novels include Peter Camenzind, Demian, Siddhartha, Steppenwolf, Narcissus and Goldmund, The Glass Bead Game, and Journey to the East. Siddhartha and Steppenwolf became cult books among the counterculture of the 1960s and 1970s. Hesse was awarded the Nobel Prize in Literature in 1946. He passed away on August 9, 1962, in Montagnola, Switzerland.', 'Dead', '1877-07-02', 'author-159-hermann-hesse.jpg'),
(160, 'Rosner', 'Hilda', 'Hilda Rosner was a translator of German literature into English, best known for her translation of Hermann Hesse\'s novel Narcissus and Goldmund, published in English as Narziss and Goldmund. Her translation work helped bring Hesse\'s meditative philosophical fiction to English-speaking audiences during the period of Hesse\'s enormous popular revival in the 1960s and 1970s. Rosner\'s translations contributed to the dissemination of German modernist literature in the English-speaking world.', 'Dead', '1914-01-01', 'author-160-hilda-rosner.jpg');
INSERT INTO `auteur` (`idAuteur`, `nom`, `prenom`, `description`, `status`, `dateNaiss`, `image`) VALUES
(161, 'Capote', 'Truman', 'Truman Garcia Capote was an American author, screenwriter, playwright, and actor born on September 30, 1924, in New Orleans, Louisiana. He was a child prodigy who began writing at age nine and was recognized early as a major literary talent. Capote is known for his distinctive and highly stylized prose and for working across a wide range of genres, from the Southern Gothic novella Other Voices, Other Rooms to the bittersweet novella Breakfast at Tiffany\'s. His masterwork, In Cold Blood, published in 1966, is a meticulously researched account of the 1959 murders of the Clutter family in Holcomb, Kansas, which Capote spent six years investigating. The book is widely considered the founding text of the true crime narrative genre and one of the greatest works of nonfiction in American literature. Capote was a celebrated figure in New York society and a close friend of Harper Lee, who helped him with research for In Cold Blood. He passed away on August 25, 1984.', 'Dead', '1924-09-30', 'author-161-truman-capote.jpg'),
(162, 'Garcia', 'Kami', 'Kami Garcia is an American young adult author who grew up in a small Southern town. She taught English and Special Education for many years in Montgomery County, Maryland, before turning to fiction. Garcia co-authored the Beautiful Creatures series with Margaret Stohl, a supernatural young adult saga set in a fictional Southern town called Gatlin. Beautiful Creatures, the first book in the series, was published in 2009 and became an international bestseller, adapted into a film in 2013. Garcia has also written the solo Young Adult series The Legion and a graphic novel series. Her work is known for its Southern Gothic atmosphere, its richly developed supernatural mythology, and its exploration of the experience of young people caught between normal life and extraordinary destinies.', 'Alive', '1972-01-01', 'author-162-kami-garcia.jpg'),
(163, 'Stohl', 'Margaret', 'Margaret Stohl is an American author and game designer born on November 14, 1967. She studied English and American literature at Yale University and Magdalen College, Oxford, and worked as a video game designer, creating games for companies including Electronic Arts, before co-writing the Beautiful Creatures series with Kami Garcia. The Beautiful Creatures series is a supernatural young adult saga set in the American South, beginning with Beautiful Creatures, published in 2009. The series became an international bestseller and was adapted into a film in 2013. Stohl has also written solo novels, including the Icons science fiction series and Black Widow: Forever Red, a Marvel novel. She is known for her vivid world-building, her ability to blend mythology and fantasy with contemporary settings, and her work bridging popular genres.', 'Alive', '1967-01-01', 'author-163-margaret-stohl.jpg'),
(164, 'Morgenstern', 'Erin', 'Erin Morgenstern is an American author and artist born on July 8, 1978, in Marshfield, Massachusetts. She studied theatre arts at Wheaton College in Massachusetts and works as a painter and digital artist as well as a novelist. Morgenstern spent several years working on her debut novel during National Novel Writing Month before finding an agent and a publisher. The Night Circus, published in 2011, is a richly atmospheric fantasy about two young magicians who are raised as rivals and pitted against each other in a mysterious competition at a magical circus that appears without warning and operates only at night. The novel became an international bestseller, praised for its gorgeous prose, immersive world-building, and fairy tale atmosphere. It spent months on bestseller lists around the world. Morgenstern\'s second novel, The Starless Sea, was published in 2019 to similar acclaim.', 'Alive', '1978-07-08', 'author-164-erin-morgenstern.jpg'),
(165, 'Gregory', 'Philippa', 'Philippa Gregory is a British historical novelist born on January 9, 1954, in Nairobi, Kenya, who grew up in England. She studied history at the University of Sussex and later earned a Ph.D. in eighteenth-century literature from the University of Edinburgh. Gregory began her career writing contemporary fiction but switched to historical fiction in the 1990s, finding her true calling in the rich material of the Tudor and Plantagenet dynasties. Her breakthrough novel, The Other Boleyn Girl, published in 2001, tells the story of Mary Boleyn, sister of Anne Boleyn, and her rivalry for the affections of Henry VIII. The novel was adapted into a BBC television film and a major Hollywood film in 2008. Gregory\'s subsequent series, The Cousins\' War, covers the Wars of the Roses, beginning with The White Queen. Her books are known for their meticulous research and their focus on the lives and perspectives of women who were often marginalized by traditional historical accounts.', 'Alive', '1954-01-09', 'author-165-philippa-gregory.jpg'),
(166, 'Westerfeld', 'Scott', 'Scott Westerfeld is an American science fiction and fantasy author born on May 5, 1963, in Dallas, Texas. He studied philosophy at Vassar College and lived in New York City and Sydney, Australia, before eventually settling in Australia. Westerfeld is known for his imaginative and socially engaged young adult science fiction, particularly his Uglies series, beginning with Uglies, published in 2005. The series is set in a future society where everyone undergoes surgery at the age of sixteen to become physically perfect, and follows a girl who questions this system. The series was a massive success and spawned multiple sequels and a Netflix film adaptation. Westerfeld is also the author of the Leviathan steampunk alternate history trilogy and the Midnighters series. His work is known for its inventive world-building, sharp social commentary, and fast-paced narratives.', 'Alive', '1963-05-05', 'author-166-scott-westerfeld.jpg'),
(167, 'Strayed', 'Cheryl', 'Cheryl Strayed is an American memoirist and novelist born on September 17, 1968, in Spangler, Pennsylvania. She grew up in rural Minnesota and studied English at the University of Minnesota. After the death of her mother from cancer and the subsequent dissolution of her marriage and struggles with heroin addiction, Strayed hiked over a thousand miles of the Pacific Crest Trail alone, with no prior hiking experience. Her memoir Wild: From Lost to Found on the Pacific Crest Trail, published in 2012, documents this journey and became a massive bestseller after being selected for Oprah\'s Book Club 2.0. It was adapted into a film starring Reese Witherspoon in 2014. Strayed has also written the novel Torch and the essay collection Tiny Beautiful Things, in which she reveals herself as the anonymous advice columnist Dear Sugar from The Rumpus. She is celebrated for her raw emotional honesty and the life-affirming quality of her writing.', 'Alive', '1968-09-17', 'author-167-cheryl-strayed.jpg'),
(168, 'Moore', 'Alan', 'Alan Moore is a British comic book writer born on November 18, 1953, in Northampton, England. He is widely regarded as the greatest writer in the history of comics and is responsible for transforming the medium into a vehicle for serious literary and political expression. Moore worked in various jobs, including as a journalist, before breaking into comics. His major works include the groundbreaking Swamp Thing run for DC Comics, Watchmen, drawn by Dave Gibbons, which deconstructs the superhero genre with adult themes and a sophisticated narrative structure, and V for Vendetta, a dystopian political thriller about fascism and anarchism. Watchmen was named one of Time magazine\'s hundred best English-language novels. Moore also wrote Batman: The Killing Joke and From Hell, a detailed graphic novel about Jack the Ripper. He is famously critical of the Hollywood adaptations of his work and has had his name removed from the credits of all film adaptations.', 'Alive', '1953-11-18', 'author-168-alan-moore.jpg'),
(169, 'Gibbons', 'Dave', 'Dave Gibbons is a British comics artist and writer born in 1949 in London, England. He is best known as the artist of Watchmen, the landmark superhero deconstruction written by Alan Moore and published by DC Comics in 1986 and 1987. Gibbons\'s precise, controlled art style and his innovative use of the nine-panel grid were essential to Watchmen\'s achievement, creating a visual density and symbolic richness that complemented Moore\'s complex narrative. Watchmen was named one of Time magazine\'s hundred best English-language novels and is widely considered the greatest graphic novel ever produced. Gibbons has also worked extensively on DC\'s Green Lantern and Doctor Who adaptations, among many other projects. He has been a significant figure in the British and American comics industries for over four decades.', 'Alive', '1949-04-14', 'author-169-dave-gibbons.jpg'),
(170, 'Higgins', 'John', 'John Higgins is a British comics colorist best known for his work on Watchmen, the seminal graphic novel written by Alan Moore and illustrated by Dave Gibbons. His distinctive use of color, which employed a muted, sometimes garish palette evoking the aesthetics of pulp and pop art, was an integral part of Watchmen\'s visual identity and helped establish the book\'s atmospheric and thematic richness. Higgins has worked as a colorist on many other major British and American comics over a long career, but his contribution to Watchmen remains his most celebrated work.', 'Alive', '1949-01-01', 'author-170-john-higgins.jpg'),
(171, 'Rothfuss', 'Patrick', 'Patrick Rothfuss is an American author born on June 6, 1973, in Madison, Wisconsin. He studied chemical engineering and English at the University of Wisconsin-Stevens Point, eventually earning a degree in English. Rothfuss spent over a decade writing his debut novel before it was published. The Name of the Wind, published in 2007, is the first volume of The Kingkiller Chronicle, a fantasy trilogy narrated by the legendary hero Kvothe, who recounts the story of his own life to a traveling chronicler. The novel was immediately recognized as an extraordinary achievement in fantasy fiction and became a massive bestseller, winning several awards and attracting a passionate and devoted global readership. Its sequel The Wise Man\'s Fear was published in 2011. The long-awaited third volume, The Doors of Stone, remains in progress and is one of the most anticipated books in contemporary fantasy. Rothfuss is also known for his charitable work through Worldbuilders.', 'Alive', '1973-06-06', 'author-171-patrick-rothfuss.jpg'),
(172, 'Melville', 'Herman', 'Herman Melville was an American novelist, short story writer, and poet born on August 1, 1819, in New York City. He is best known for Moby-Dick, published in 1851, one of the greatest and most ambitious novels in American literature, a sweeping meditation on obsession, free will, fate, and the nature of evil told through Captain Ahab\'s relentless pursuit of the white whale. Melville spent years at sea as a young man, including time on a whaling ship, in the Marquesas Islands, and in the US Navy, experiences that provided the raw material for his fiction. His early sea adventures Typee and Omoo brought him popular success, but Moby-Dick received a mixed reception on publication and Melville spent the rest of his life in relative obscurity, working as a customs inspector in New York for nearly twenty years. His reputation was dramatically revived in the 1920s, when he was recognized as a major American literary figure. He passed away on September 28, 1891.', 'Dead', '1819-08-01', 'author-172-herman-melville.jpg'),
(173, 'Delbanco', 'Andrew', 'Andrew Delbanco is an American literary scholar and public intellectual born on February 20, 1952. He is the Alexander Hamilton Professor of American Studies at Columbia University, where he is also the director of American Studies. Delbanco is known for his influential works on American literature, history, and education, including studies of Herman Melville, the Puritan tradition in American culture, and the history and purpose of the American university. His book Melville: His World and Work is considered one of the finest literary biographies of the American author. Delbanco is also a prominent voice in debates about higher education and the liberal arts in America.', 'Alive', '1952-01-01', 'author-173-andrew-delbanco.jpg'),
(174, 'Quirk', 'Tom', 'Tom Quirk is an American literary scholar known for his academic work on nineteenth-century American literature, particularly on Mark Twain and the broader context of American Realism. He has written and edited several studies of Twain and of the short story form in American literature, contributing to scholarly understanding of these important literary traditions. Quirk has been a professor at the University of Missouri and his work is considered valuable for anyone studying the development of American narrative fiction.', 'Alive', '1946-01-01', 'author-174-tom-quirk.jpg'),
(175, 'Harris', 'Charlaine', 'Charlaine Harris is an American author born on November 25, 1951, in Tunica, Mississippi. She studied English and drama at Rhodes College in Memphis, Tennessee. Harris is best known for the Southern Vampire Mysteries, also known as the Sookie Stackhouse novels, a series of paranormal mystery novels set in the fictional Louisiana town of Bon Temps, where vampires have come out of the closet to live openly among humans. The series, which begins with Dead Until Dark, published in 2001, became the basis for the hugely successful HBO television series True Blood, which ran from 2008 to 2014. Harris has written thirteen books in the Sookie Stackhouse series as well as other mystery series, including the Lily Bard and Aurora Teagarden series. She is widely credited with helping to popularize the paranormal romance and Southern Gothic subgenres in popular fiction.', 'Alive', '1951-11-25', 'author-175-charlaine-harris.jpg'),
(176, 'Grogan', 'John', 'John Grogan is an American journalist and author born in 1957 in Michigan. He worked for many years as a newspaper journalist and columnist, including at The Philadelphia Inquirer. Grogan is best known for his memoir Marley and Me: Life and Love with the World\'s Worst Dog, published in 2005, which grew out of a newspaper column he wrote about his family\'s beloved but wildly unruly yellow Labrador retriever, Marley. The book became one of the bestselling memoirs in American publishing history, spending over two years on the New York Times bestseller list, and was adapted into a major Hollywood film starring Owen Wilson and Jennifer Aniston in 2008. Marley and Me is a warmly humorous and ultimately deeply moving account of the bond between a family and their dog, and has been read and loved by millions of pet owners worldwide.', 'Alive', '1957-06-28', 'author-176-john-grogan.jpg'),
(177, 'Christie', 'Agatha', 'Dame Agatha Mary Clarissa Christie was a British crime novelist, short story writer, and playwright born on September 15, 1890, in Torquay, Devon, England. She is the bestselling novelist of all time, with only the Bible and Shakespeare having sold more copies. Her works have sold over two billion copies worldwide and have been translated into over 103 languages. Christie is best known for creating two iconic fictional detectives: the fastidious Belgian Hercule Poirot and the deceptively mild-mannered Miss Jane Marple. Her novel And Then There Were None is the bestselling mystery novel of all time. Christie worked as a nurse during World War I, where she gained knowledge of poisons that she would use extensively in her fiction. She was also an accomplished archaeologist who participated in excavations in the Middle East alongside her second husband Max Mallowan. She was made a Dame Commander of the British Empire in 1971. Christie died on January 12, 1976.', 'Dead', '1890-09-15', 'author-177-agatha-christie.jpg'),
(178, 'Fitzpatrick', 'Becca', 'Becca Fitzpatrick is an American young adult author known for the Hush, Hush series, a paranormal romance saga featuring fallen angels. Her debut novel Hush, Hush, published in 2009, became a New York Times bestseller and the series grew to four books, each reaching the bestseller lists. Fitzpatrick studied health and exercise science at Colorado State University before pursuing her passion for writing. Her novels are known for their romantic tension, supernatural atmosphere, and the blend of angelic mythology with contemporary teenage life.', 'Alive', '1979-01-01', 'author-178-becca-fitzpatrick.jpg'),
(179, 'McGuire', 'Jamie', 'Jamie McGuire is an American author known for her New Adult romance novel Beautiful Disaster, self-published in 2011, which became one of the most successful independently published novels of its era before being acquired by a major publisher. The novel tells the story of a good girl who falls for a dangerous, tattooed bad boy at college, and its compulsive readability and passionate online following helped pioneer the New Adult genre, which focuses on characters in their late teens and early twenties navigating college, independence, and first serious relationships. McGuire has written numerous other romance novels and is one of the most commercially successful self-published authors in the history of the industry.', 'Alive', '1978-12-28', 'author-179-mcguire-jamie.jpg'),
(180, 'Rice', 'Anne', 'Anne Rice was an American author born on October 4, 1941, in New Orleans, Louisiana. She is best known for her gothic fiction, particularly The Vampire Chronicles, a series of novels that began with Interview with the Vampire in 1976. The novel, narrated by the vampire Louis de Pointe du Lac to a journalist, introduced a new model of the romantic, existential vampire and transformed popular conceptions of the figure. It was adapted into a major film in 1994 starring Tom Cruise and Brad Pitt, and later into a television series. The Vampire Chronicles grew to thirteen novels. Rice also wrote the Mayfair Witches series and, after a period of deep Catholic faith, wrote novels about the life of Jesus Christ from Jesus\'s own perspective. She grew up in New Orleans and the city permeates her fiction with its atmosphere of decadence, history, and the supernatural. Rice passed away on December 11, 2021.', 'Dead', '1941-10-04', 'author-180-anne-rice.jpg'),
(181, 'Cass', 'Kiera', 'Kiera Cass is an American young adult author born on May 19, 1981, in South Carolina. She attended Coastal Carolina University and later Radford University, where she studied history. Cass is best known for The Selection series, a dystopian romance that imagines a future America as a monarchy where a prince selects his bride from a competition among thirty-five young women, blending elements of The Hunger Games with The Bachelor. The Selection, published in 2012, became a New York Times bestseller and spawned five books in the main series as well as companion novellas. The series was announced as a television adaptation for The CW network. Cass is known for her romantic, character-driven storytelling and her ability to blend fairy tale and dystopian elements in an entertaining and commercially successful way.', 'Alive', '1981-05-19', 'author-181-kiera-cass.jpg'),
(182, 'Evanovich', 'Janet', 'Janet Evanovich is an American author born on April 22, 1943, in South River, New Jersey. She studied fine arts at Douglass College, Rutgers University. Evanovich began her career writing romance novels under the pseudonym Steffie Hall before transitioning to crime fiction. She is best known for the Stephanie Plum series, which began with One for the Money in 1994. The series features Stephanie Plum, a brash New Jersey bounty hunter, and is known for its slapstick comedy, sexual tension, and vivid working-class New Jersey setting. The series has sold over one hundred million copies worldwide and consistently lands on bestseller lists. One for the Money was adapted into a film in 2012. Evanovich is one of the bestselling crime fiction authors in the world and has also co-written several other series with other authors.', 'Alive', '1943-04-22', 'author-182-janet-evanovich.jpg'),
(183, 'Skloot', 'Rebecca', 'Rebecca Skloot is an American science writer born on September 19, 1972, in Springfield, Illinois. She studied animal science at Colorado State University and earned her master\'s degree in creative nonfiction from the University of Pittsburgh. Skloot spent over ten years researching and writing The Immortal Life of Henrietta Lacks, published in 2010, which tells the story of Henrietta Lacks, a Black woman from Baltimore whose cancer cells were taken without her knowledge in 1951 and became one of the most important tools in medicine, used in the development of the polio vaccine, cancer research, and countless other medical advances. The book raises important questions about medical ethics, race, and consent and became a major bestseller, spending over six years on the New York Times list. It was adapted into an HBO film starring Oprah Winfrey in 2017. Skloot founded the Henrietta Lacks Foundation to provide scholarships and financial assistance to Lacks\'s descendants.', 'Alive', '1972-02-07', 'author-183-rebecca-skloot.jpg'),
(184, 'Harris', 'Thomas', 'Thomas Harris is an American author born on April 11, 1940, in Jackson, Tennessee. He studied English at Baylor University and worked as a police reporter before turning to fiction. Harris is the creator of the iconic fictional serial killer Dr. Hannibal Lecter, one of the most memorable villains in American literature and popular culture. Lecter was introduced in Red Dragon, published in 1981, and became central in The Silence of the Lambs, published in 1988, in which FBI trainee Clarice Starling seeks Lecter\'s help to catch another serial killer. The Silence of the Lambs won the Big Five awards in the mystery genre and was adapted into an Oscar-sweeping film in 1991, one of only three films to win Best Picture, Director, Actor, Actress, and Screenplay. Harris\'s influence on the crime and psychological thriller genres is immense. He is a notoriously reclusive and slow-publishing author who has produced only a handful of novels over his career.', 'Alive', '1940-04-11', 'author-184-thomas-harris.jpg'),
(185, 'Mead', 'Richelle', 'Richelle Mead is an American fantasy and paranormal romance author known primarily for the Vampire Academy series, a young adult saga set at a boarding school for vampires and their half-human guardians called dhampirs. The series, beginning with Vampire Academy, published in 2007, grew to six books and became an international bestseller, translated into dozens of languages. The series was adapted into a film in 2014. Mead studied comparative religion at the University of Michigan and has also written the Bloodlines spin-off series and the Georgina Kincaid adult urban fantasy series. She is known for her fast-paced storytelling, strong heroines, and her ability to create richly developed supernatural worlds that feel contemporary and exciting.', 'Alive', '1976-02-12', 'author-185-richelle-mead.jpg'),
(186, 'McEwan', 'Ian', 'Ian Russell McEwan is a British novelist and screenwriter born on June 21, 1948, in Aldershot, Hampshire, England. He studied English at the University of Sussex and earned his MA in creative writing from the University of East Anglia, where he was one of the first students in the program. McEwan is one of the most critically acclaimed British novelists of his generation and has won numerous awards including the Man Booker Prize for Amsterdam in 1998. His work is known for its psychological intensity, moral seriousness, and ability to explore the dark undercurrents of everyday life. His novel Atonement, published in 2001, is widely considered his masterpiece, telling the story of a young girl\'s false accusation and its devastating lifelong consequences, and is a profound meditation on guilt, memory, and the power of storytelling. It was adapted into a BAFTA and Oscar-nominated film starring Keira Knightley and James McAvoy in 2007. McEwan\'s other notable works include Enduring Love, Saturday, and The Children Act.', 'Alive', '1948-06-21', 'author-186-ian-mcewan.jpg'),
(187, 'Kafka', 'Franz', 'Franz Kafka was a German-speaking Bohemian novelist and short-story writer born on July 3, 1883, in Prague, then part of the Austro-Hungarian Empire. He is one of the most influential and widely studied authors of the twentieth century, despite publishing relatively little during his own lifetime and famously requesting that his manuscripts be burned after his death. Kafka\'s work, much of which was published posthumously by his friend Max Brod, is characterized by nightmarish, surreal scenarios in which ordinary individuals struggle against incomprehensible bureaucratic forces, impersonal authority, and existential alienation. His major works include the novella The Metamorphosis, in which a man wakes to find himself transformed into a giant insect, and the unfinished novels The Trial and The Castle. The term Kafkaesque has entered the language to describe situations of oppressive, absurdist, nightmarish bureaucracy. Kafka earned a doctorate in law and worked in insurance while writing in his spare time. He died of tuberculosis on June 3, 1924.', 'Dead', '1883-07-03', 'author-187-franz-kafka.jpg'),
(188, 'Corngold', 'Stanley', 'Stanley Corngold is an American literary scholar and translator born in 1934, known for his influential work on Franz Kafka and other German-language modernist authors. He is a professor emeritus of German and comparative literature at Princeton University. Corngold\'s 1972 translation of Kafka\'s The Metamorphosis, together with his critical commentary on the story\'s central image, is considered one of the most rigorous and influential translations and analyses of the work. He has also written extensively on Thomas Mann, Friedrich Nietzsche, and other major figures of German literature. His scholarship is distinguished by its philosophical depth and its close attention to the complexities of language and translation.', 'Alive', '1934-06-11', 'author-188-stanley-corngold.jpg'),
(189, 'Cline', 'Ernest', 'Ernest Cline is an American author, screenwriter, and spoken word artist born on March 29, 1972, in Ashland, Ohio. He grew up as a devoted fan of 1980s pop culture, video games, and science fiction, all of which form the substrate of his fiction. Cline worked as a spoken word performer and screenwriter before publishing his debut novel Ready Player One in 2011. The novel is set in a near-future dystopia where most of humanity spends its time in a massive virtual reality simulation called the OASIS. When the creator of the OASIS dies and leaves his fortune hidden in a series of pop culture puzzles within the simulation, teenager Wade Watts joins the hunt. The novel became a massive bestseller and was adapted into a film by Steven Spielberg in 2018. Ready Player One\'s celebration of geek culture and 1980s nostalgia resonated deeply with millions of readers. Cline is also the author of the sequel Armada and Ready Player Two.', 'Alive', '1972-03-29', 'author-189-ernest-cline.jpg'),
(190, 'Stein', 'Garth', 'Garth Stein is an American author and playwright born on December 6, 1964, in Seattle, Washington. He studied film at Columbia University and has worked as a documentary filmmaker as well as a novelist. Stein is best known for The Art of Racing in the Rain, published in 2008, a novel narrated by Enzo, a dog who believes he will be reincarnated as a human after his death and who observes the life of his owner, a race car driver, with philosophical wisdom and profound affection. The novel became a major bestseller and was adapted into a film starring Milo Ventimiglia in 2019. Stein\'s novel is celebrated for its unique narrative voice, its meditation on loyalty, loss, and the human capacity for resilience, and its ability to make readers fall in love with a canine narrator.', 'Alive', '1964-05-08', 'author-190-garth-stein.jpg'),
(191, 'Day', 'Sylvia', 'Sylvia Day is an American author born on March 11, 1973, in Los Angeles, California. She served in the US Army Military Intelligence before becoming a full-time author. Day writes erotic romance and paranormal romance fiction under several pen names. She is best known for the Crossfire series, beginning with Bared to You, published in 2012. The series, which follows the intense and complicated love story between Gideon Cross, a billionaire with a dark past, and Evangeline Tramell, became a massive global bestseller, in part riding the wave of interest in adult erotic romance that followed the Fifty Shades of Grey phenomenon. The Crossfire series has sold over thirty million copies worldwide. Day is one of the most successful erotic romance authors in the world and has been published in over forty countries.', 'Alive', '1973-03-06', 'author-191-sylvia-day.jpg'),
(192, 'Baynes', 'Pauline', 'Pauline Diana Baynes was a British illustrator born on September 9, 1922, in Hove, Sussex, England. She is best known for her illustrations of C.S. Lewis\'s Chronicles of Narnia and J.R.R. Tolkien\'s Farmer Giles of Ham and other works. Baynes studied at the Slade School of Fine Art and worked in the department of maritime design during World War II. Her delicate, detailed, and evocative illustrations for The Lion, the Witch and the Wardrobe and its sequels, as well as for Tolkien\'s medieval fantasy tales, have become iconic and helped define the visual world of these beloved books for generations of readers. Lewis himself was so delighted by her illustrations that he praised them as surpassing his own imagining of Narnia. Baynes continued illustrating books and other projects throughout a long and celebrated career. She passed away on August 1, 2008.', 'Dead', '1922-09-09', 'author-192-baynes-pauline.jpg'),
(193, 'Cotta Vaz', 'Mark', 'Mark Cotta Vaz is an American author and entertainment journalist known for writing numerous books about film history, filmmaking, and popular culture, particularly relating to major Hollywood franchises. He has written official companion books and behind-the-scenes volumes for major film series including The Twilight Saga, Indiana Jones, and many others. Cotta Vaz\'s books are notable for their access to production materials, concept art, and interviews with filmmakers, and are popular with fans seeking in-depth looks at the making of their favorite films.', 'Alive', '1954-09-20', 'author-193-cotta-vaz-mark.jpg'),
(194, 'Pelzer', 'Dave', 'Dave Pelzer is an American author born on December 29, 1960, in San Francisco, California. He is known primarily for his memoirs documenting his experiences as a child abuse survivor. His book A Child Called It, published in 1995, describes the severe physical and emotional abuse he suffered at the hands of his alcoholic mother during childhood, abuse so extreme that it was identified by authorities as one of the most severe cases of child abuse in California history. He was removed from his home at the age of twelve. The book became one of the longest-running nonfiction bestsellers in American publishing history and is credited with raising awareness of child abuse and its devastating effects. Pelzer followed it with two sequels, The Lost Boy and A Man Named Dave. He works as a motivational speaker and advocate for child welfare and has received recognition from five American presidents for his work inspiring at-risk youth.', 'Alive', '1960-12-29', 'author-194-dave-pelzer.jpg');
